import type { setupTreeNodeViewBindings } from './view-bindings/setup'

interface CreateUseTreeNodeViewBindingsExposedOptions {
  setupResult: ReturnType<typeof setupTreeNodeViewBindings>
}

export function createUseTreeNodeViewBindingsExposed(options: CreateUseTreeNodeViewBindingsExposedOptions) {
  const { setupResult } = options

  return {
    hasError: setupResult.exposedBindings.hasError,
    indentSize: setupResult.exposedBindings.indentSize,
    nodeClasses: setupResult.exposedBindings.nodeClasses,
    getAvailableOperators: setupResult.exposedBindings.getAvailableOperators,
    shellListeners: setupResult.listeners.shellListeners,
    contentListeners: setupResult.listeners.contentListeners,
    childrenListeners: setupResult.listeners.childrenListeners,
  }
}
