import { createParameterValueEditorExposedBindings } from './parameter-value-bindings/exposed'
import { setupParameterValueEditorBindings } from './parameter-value-bindings/setup'
import type { ParameterValueEditorEmits, ParameterValueEditorProps } from './parameter-value-bindings/types'

export type { ParameterValueEditorEmits, ParameterValueEditorProps } from './parameter-value-bindings/types'

interface UseParameterValueEditorBindingsOptions {
  props: ParameterValueEditorProps
  emit: ParameterValueEditorEmits
}

export function useParameterValueEditorBindings(options: UseParameterValueEditorBindingsOptions) {
  const setupResult = setupParameterValueEditorBindings(options)
  return createParameterValueEditorExposedBindings({ setupResult })
}
