import { createFunctionRefEditorExposedBindings } from './function-ref-bindings/exposed'
import { setupFunctionRefEditorBindings } from './function-ref-bindings/setup'
import type { FunctionRefEditorEmits, FunctionRefEditorProps } from './function-ref-bindings/types'

export type { FunctionRefEditorEmits, FunctionRefEditorProps } from './function-ref-bindings/types'

interface UseFunctionRefEditorBindingsOptions {
  props: FunctionRefEditorProps
  emit: FunctionRefEditorEmits
}

export function useFunctionRefEditorBindings(options: UseFunctionRefEditorBindingsOptions) {
  const setupResult = setupFunctionRefEditorBindings(options)
  return createFunctionRefEditorExposedBindings({ setupResult })
}
