import type { Ref } from 'vue'
import type { DragPosition } from '../useTreeNodeController.types'
import { resolveDragPosition } from './position'
import { getCurrentTargetRect } from './style'

interface DragOverDropOptions {
  nodeId: string
  nodeType: 'group' | 'condition'
  isDragOver: Ref<boolean>
  dragPosition: Ref<DragPosition | null>
  emitDragNode: (sourceNodeId: string, targetNodeId: string, position: DragPosition) => void
  clearAllDragStates: () => void
}

export function createTreeNodeDragOverDropHandlers(options: DragOverDropOptions) {
  const {
    nodeId,
    nodeType,
    isDragOver,
    dragPosition,
    emitDragNode,
    clearAllDragStates,
  } = options

  const handleDragOver = (event: DragEvent) => {
    event.preventDefault()
    event.stopPropagation()

    if (!event.dataTransfer) {
      return
    }

    const sourceNodeId = event.dataTransfer.getData('text/plain')
    if (sourceNodeId === nodeId) {
      event.dataTransfer.dropEffect = 'none'
      return
    }

    event.dataTransfer.dropEffect = 'move'
    isDragOver.value = true

    const rect = getCurrentTargetRect(event)
    if (!rect) {
      return
    }

    const y = event.clientY - rect.top
    dragPosition.value = resolveDragPosition(nodeType, y, rect.height)
  }

  const handleDrop = (event: DragEvent) => {
    event.preventDefault()
    event.stopPropagation()

    if (!event.dataTransfer) {
      return
    }

    const sourceNodeId = event.dataTransfer.getData('text/plain')
    if (sourceNodeId === nodeId) {
      clearAllDragStates()
      return
    }

    if (dragPosition.value) {
      emitDragNode(sourceNodeId, nodeId, dragPosition.value)
    }
    clearAllDragStates()
  }

  return {
    handleDragOver,
    handleDrop,
  }
}
