import { createTreeCanvasExposedBindings } from './tree-canvas-bindings/exposed'
import { setupTreeCanvasBindings } from './tree-canvas-bindings/setup'
import type { UseTreeCanvasBindingsOptions } from './tree-canvas-bindings/types'

export type { UseTreeCanvasBindingsOptions } from './tree-canvas-bindings/types'

export function useTreeCanvasBindings(options: UseTreeCanvasBindingsOptions) {
  const setupResult = setupTreeCanvasBindings(options)
  return createTreeCanvasExposedBindings({ setupResult })
}
