import { computed } from 'vue'
import type { ValueInputSwitchPanelProps } from '../switch-panel/types'

export function createValueInputSwitchPanelSelectorProps(props: ValueInputSwitchPanelProps) {
  return computed(() => ({
    modelValue: props.currentInputType,
    options: props.valueTypeOptions,
    placeholder: '值类型',
  }))
}
