import type { AviatorFunction, FieldOption } from '../../../infrastructure/engine/types'
import { COMPOUND_OPERATORS, type ValueInputType } from './constants'
import { getBaseFieldNameFromReference } from './fieldReference'

export function isCompoundComparison(comparison?: string): boolean {
  if (!comparison) return false
  return COMPOUND_OPERATORS.has(comparison)
}

export function resolveValueInputType(params: {
  explicitType?: string | null
  value: unknown
  valueIsLiteral?: boolean
  availableFields?: readonly FieldOption[]
  functions: readonly AviatorFunction[]
}): ValueInputType {
  const { explicitType, value, valueIsLiteral, availableFields, functions } = params

  if (isValueInputType(explicitType)) {
    return explicitType
  }

  if (valueIsLiteral === true) {
    return 'value'
  }

  const valueText = typeof value === 'string' ? value : ''

  if (valueText && availableFields?.some((field) => field.value === valueText)) {
    return 'field'
  }

  if (valueText && /^[a-z_][\w.]*\[[^\]]+\]/i.test(valueText)) {
    const baseFieldName = getBaseFieldNameFromReference(valueText)
    if (baseFieldName && availableFields?.some((field) => field.value === baseFieldName)) {
      return 'field'
    }
  }

  if (valueText) {
    const funcCallMatch = valueText.match(/^([a-z_][\w.]*)\s*\(/i)
    if (funcCallMatch) {
      const functionName = funcCallMatch[1]
      if (functions.some((fn) => fn.name === functionName)) {
        return 'function'
      }
    }
  }

  return 'value'
}

function isValueInputType(value: unknown): value is ValueInputType {
  return value === 'value' || value === 'field' || value === 'function'
}
