import type { TreeNode } from '../../types'
import { reassignCopiedSubtreeIds } from './copy-reassign'
import { cloneDataTypes, deepCloneNode, generateCopiedNodeId } from './copy-utils'

interface FindAndCloneNodeOptions {
  nodes: TreeNode[]
  nodeId: string
  parameterDataTypes: Map<string, Map<string, string>>
}

export function findAndCloneNode(options: FindAndCloneNodeOptions): TreeNode | null {
  const { nodes, nodeId, parameterDataTypes } = options

  for (const node of nodes) {
    if (node.id === nodeId) {
      const copiedNode = deepCloneNode(node)
      copiedNode.id = generateCopiedNodeId(node.type)

      reassignCopiedSubtreeIds({
        targetNode: copiedNode,
        parameterDataTypes,
        parentId: node.parentId,
      })
      cloneDataTypes(parameterDataTypes, node.id, copiedNode.id)
      return copiedNode
    }

    if (node.children) {
      const found = findAndCloneNode({
        nodes: node.children,
        nodeId,
        parameterDataTypes,
      })
      if (found) return found
    }
  }

  return null
}

interface InsertCopiedNodeOptions {
  nodes: TreeNode[]
  targetId: string
  copiedNode: TreeNode
}

export function insertCopiedNode(options: InsertCopiedNodeOptions): boolean {
  const { nodes, targetId, copiedNode } = options
  const index = nodes.findIndex((node) => node.id === targetId)
  if (index >= 0) {
    nodes.splice(index + 1, 0, copiedNode)
    return true
  }

  for (const node of nodes) {
    if (node.children && insertCopiedNode({
      nodes: node.children,
      targetId,
      copiedNode,
    })) {
      return true
    }
  }

  return false
}
