import type { NodeValue, TreeNode } from '../../infrastructure/engine/types'

const VALUELESS_COMPARISONS = new Set(['== nil', '!= nil', '== \'\'', '!= \'\''])

export function createComparisonUpdates(
  node: TreeNode,
  comparison: string,
): Partial<TreeNode> {
  const needsValue = !VALUELESS_COMPARISONS.has(comparison)
  if (!needsValue) {
    return {
      comparison,
      value: undefined,
    }
  }

  const updates: Partial<TreeNode> = { comparison }
  if (comparison === 'match' && !node.extraComparison) {
    updates.extraComparison = '== nil'
  } else if (comparison !== 'match' && node.extraComparison) {
    updates.extraComparison = undefined
  }
  return updates
}

export function createValueUpdates(value: NodeValue): Partial<TreeNode> {
  return { value }
}

export function createExtraComparisonUpdates(value: string | undefined): Partial<TreeNode> {
  return { extraComparison: value }
}
