import type { NodeValue } from '../../../../../../infrastructure/engine/types'
import type { UseFunctionParameterItemBindingsOptions } from './types'

export function createFunctionParameterItemListeners(options: UseFunctionParameterItemBindingsOptions) {
  const { props, emit } = options

  const parameterInputListeners = {
    'update:value': (value: NodeValue) => emit('update:parameter', { paramName: props.paramName, value }),
    'update:type': (paramName: string, type: string) => emit('update:parameter-type', { paramName, type }),
    'update:value-data-type': (paramName: string, dataType: string) => {
      emit('update:parameter-value-type', { paramName, dataType })
    },
  } as const

  return {
    parameterInputListeners,
  }
}
