import type { createParameterInputBaseListeners } from './listeners.base'
import type { createParameterInputConditionModeListeners } from './listeners.condition'

interface CreateParameterInputListenersExposedOptions {
  baseListeners: ReturnType<typeof createParameterInputBaseListeners>
  conditionListeners: ReturnType<typeof createParameterInputConditionModeListeners>
}

export function createParameterInputListenersExposed(
  options: CreateParameterInputListenersExposedOptions,
) {
  const { baseListeners, conditionListeners } = options

  return {
    typeSelectorListeners: baseListeners.typeSelectorListeners,
    valueModeListeners: baseListeners.valueModeListeners,
    fieldModeListeners: baseListeners.fieldModeListeners,
    lambdaModeListeners: baseListeners.lambdaModeListeners,
    conditionModeListeners: conditionListeners.conditionModeListeners,
  }
}
