import type { setupTreeNodeContentBindings } from './setup'

interface CreateTreeNodeContentExposedBindingsOptions {
  setupResult: ReturnType<typeof setupTreeNodeContentBindings>
}

export function createTreeNodeContentExposedBindings(options: CreateTreeNodeContentExposedBindingsOptions) {
  const { dragBindings, listeners } = options.setupResult

  return {
    onDragStart: dragBindings.onDragStart,
    onDragEnd: dragBindings.onDragEnd,
    affordanceListeners: listeners.affordanceListeners,
    editorListeners: listeners.editorListeners,
    actionListeners: listeners.actionListeners,
  }
}
