import type { NodeValue } from '../../../../infrastructure/engine/types'
import type {
  ParameterTypePayload,
  ParameterValuePayload,
  ParameterValueTypePayload,
  ValueDataTypePayload,
} from '../../../types/nodeEditorPayloads'
import type { TreeNodeContentEmits } from './types'

export function createTreeNodeContentEditorBindings(emit: TreeNodeContentEmits) {
  const onConditionNegation = (value: boolean) => emit('update:condition-negation', value)
  const onSwitchMode = (mode: 'condition' | 'function') => emit('switch:mode', mode)
  const onUpdateField = (value: string) => emit('update:field', value)
  const onUpdateArrayIndex = (value: number | undefined) => emit('update:array-index', value)
  const onUpdateComparison = (value: string) => emit('update:comparison', value)
  const onUpdateValue = (value: NodeValue) => emit('update:value', value)
  const onUpdateExtraComparison = (value: string | undefined) => emit('update:extra-comparison', value)
  const onUpdateValueDataType = (payload: ValueDataTypePayload) => emit('update:value-data-type', payload)
  const onUpdateFunction = (functionName: string) => emit('update:function', functionName)
  const onUpdateParameter = (payload: ParameterValuePayload) => emit('update:parameter', payload)
  const onUpdateParameterType = (payload: ParameterTypePayload) => emit('update:parameter-type', payload)
  const onUpdateParameterValueType = (payload: ParameterValueTypePayload) => emit('update:parameter-value-type', payload)
  const onUpdateFunctionValueDataType = (payload: ValueDataTypePayload) => emit('update:function-value-data-type', payload)
  const onUpdateGroupOperator = (value: 'AND' | 'OR') => emit('update:group-operator', value)
  const onUpdateGroupNegation = (value: boolean) => emit('update:group-negation', value)

  return {
    onConditionNegation,
    onSwitchMode,
    onUpdateField,
    onUpdateArrayIndex,
    onUpdateComparison,
    onUpdateValue,
    onUpdateExtraComparison,
    onUpdateValueDataType,
    onUpdateFunction,
    onUpdateParameter,
    onUpdateParameterType,
    onUpdateParameterValueType,
    onUpdateFunctionValueDataType,
    onUpdateGroupOperator,
    onUpdateGroupNegation,
  }
}
