import type { setupFunctionSelectPanelBindings } from './setup'

interface CreateFunctionSelectPanelExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionSelectPanelBindings>
}

export function createFunctionSelectPanelExposedBindings(
  options: CreateFunctionSelectPanelExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    onUpdateFunction: setupResult.onUpdateFunction,
    onShowUsage: setupResult.onShowUsage,
  }
}
