import type { setupAviatorExpressionBuilderModalBindings } from './setup'
import { createAviatorExpressionBuilderModalListeners } from './listeners'

interface CreateAviatorExpressionBuilderModalExposedBindingsOptions {
  setupResult: ReturnType<typeof setupAviatorExpressionBuilderModalBindings>
}

export function createAviatorExpressionBuilderModalExposedBindings(
  options: CreateAviatorExpressionBuilderModalExposedBindingsOptions,
) {
  const { localExpression, handleSave, handleCancel } = options.setupResult
  const listeners = createAviatorExpressionBuilderModalListeners({
    handleSave,
    handleCancel,
  })

  return {
    localExpression,
    modalListeners: listeners.modalListeners,
    footerListeners: listeners.footerListeners,
  }
}
