import type { ComputedRef, Ref } from 'vue'
import type { AviatorFunction } from '../../../infrastructure/engine/types'
import type { FunctionCategory } from '../../logic/value-input'
import type { FunctionRefParameter } from './types'
import type { createFunctionRefValueActions } from './actions'

interface CreateFunctionRefValueControllerExposedOptions {
  selectedFunctionName: Ref<string>
  functionParameters: Ref<FunctionRefParameter[]>
  functionCategories: ComputedRef<FunctionCategory[]>
  selectedFunction: ComputedRef<AviatorFunction | null>
  actions: ReturnType<typeof createFunctionRefValueActions>
}

export function createFunctionRefValueControllerExposed(
  options: CreateFunctionRefValueControllerExposedOptions,
) {
  const { selectedFunctionName, functionParameters, functionCategories, selectedFunction, actions } = options

  return {
    selectedFunctionName,
    functionParameters,
    functionCategories,
    selectedFunction,
    initializeFromExpression: actions.initializeFromExpression,
    buildExpression: actions.buildExpression,
    selectFunction: actions.selectFunction,
    setParameter: actions.setParameter,
  }
}
