import type { ValueInputSwitchPanelProps } from '../switch-panel/types'
import { createValueInputSwitchPanelBodyProps } from './panel-props.panel-body'
import { createValueInputSwitchPanelSelectorProps } from './panel-props.selector'

interface CreateValueInputSwitchPanelPanelPropsOptions {
  props: ValueInputSwitchPanelProps
}

export function createValueInputSwitchPanelPanelProps(
  options: CreateValueInputSwitchPanelPanelPropsOptions,
) {
  const { props } = options

  const selectorProps = createValueInputSwitchPanelSelectorProps(props)
  const panelBodyProps = createValueInputSwitchPanelBodyProps(props)

  return {
    selectorProps,
    panelBodyProps,
  }
}
