import type { createParameterValueEditorForwarders } from './forwarders'

interface CreateParameterValueEditorListenersOptions {
  forwarders: ReturnType<typeof createParameterValueEditorForwarders>
}

export function createParameterValueEditorListeners(options: CreateParameterValueEditorListenersOptions) {
  const { forwarders } = options

  const valueInputSwitchListeners = {
    'update:value': forwarders.onUpdateValue,
    'update:multi-values': forwarders.onUpdateMultiValues,
  } as const

  const dataTypeSwitchListeners = {
    'update:model-value': forwarders.onUpdateValueDataType,
  } as const

  return {
    valueInputSwitchListeners,
    dataTypeSwitchListeners,
  }
}
