import type { NodeValue } from '../../../../../../infrastructure/engine/types'
import type { createFunctionRefParameterInputForwarders } from './forwarders'
import type { FunctionRefParameterInputListeners, FunctionRefParameterInputProps } from './item.types'

interface CreateFunctionRefParameterItemListenersOptions {
  props: FunctionRefParameterInputProps
  forwarders: ReturnType<typeof createFunctionRefParameterInputForwarders>
}

export function createFunctionRefParameterItemListeners(
  options: CreateFunctionRefParameterItemListenersOptions,
) {
  const { props, forwarders } = options

  const inputBodyListeners: FunctionRefParameterInputListeners = {
    'update:value': (value: NodeValue) => {
      forwarders.onUpdateValue({ index: props.index, value })
    },
  }

  return {
    inputBodyListeners,
  }
}
