import { computed } from 'vue'
import type { ConditionValueInputSwitchProps } from './types'

export function createConditionValueInputSwitchPanelProps(props: ConditionValueInputSwitchProps) {
  const booleanSelectProps = computed(() => ({
    modelValue: props.value,
    compact: true,
  }))

  const nullSelectProps = computed(() => ({
    modelValue: props.value,
  }))

  const multiValueInputProps = computed(() => ({
    modelValue: props.multiValues,
    placeholder: props.multiValuePlaceholder,
    tooltip: props.multiValueTooltip,
  }))

  const urlInputProps = computed(() => ({
    modelValue: props.value,
    error: props.urlError,
  }))

  const dateTimeInputProps = computed(() => ({
    modelValue: props.dateValue,
  }))

  const fallbackInputProps = computed(() => ({
    value: props.value,
    fieldType: props.fieldType,
    valueDataType: props.valueDataType,
    placeholder: props.placeholder,
  }))

  return {
    booleanSelectProps,
    nullSelectProps,
    multiValueInputProps,
    urlInputProps,
    dateTimeInputProps,
    fallbackInputProps,
  }
}
