import type { NodeValue } from '../../../../../infrastructure/engine/types'
import type { ValueEditorEmits } from './types'

export function createValueEditorListeners(emit: ValueEditorEmits) {
  const onUpdateValue = (value: NodeValue) => emit('update:value', value)
  const onUpdateMultiValues = (values: string[]) => emit('update:multi-values', values)
  const onUpdateDateValue = (date: Date | undefined) => emit('update:date-value', date)
  const onBlurUrl = () => emit('blur:url')
  const onUpdateValueDataType = (dataType: string) => emit('update:value-data-type', dataType)

  const conditionEditorListeners = {
    'update:value': onUpdateValue,
    'update:multi-values': onUpdateMultiValues,
    'update:date-value': onUpdateDateValue,
    'blur:url': onBlurUrl,
    'update:value-data-type': onUpdateValueDataType,
  } as const

  const parameterEditorListeners = {
    'update:value': onUpdateValue,
    'update:multi-values': onUpdateMultiValues,
    'update:value-data-type': onUpdateValueDataType,
  } as const

  return {
    conditionEditorListeners,
    parameterEditorListeners,
  }
}
