import { computed } from 'vue'
import { createFunctionComparisonPanelListeners } from './listeners'
import type { FunctionComparisonPanelState, UseFunctionComparisonPanelBindingsOptions } from './types'

export function setupFunctionComparisonPanelBindings(options: UseFunctionComparisonPanelBindingsOptions) {
  const { props, emit } = options

  const currentDataType: FunctionComparisonPanelState['currentDataType'] = computed(() => {
    if (!props.getParameterDataType) return 'string'
    return props.getParameterDataType(props.node.id, props.selectedFunction.name) || 'string'
  })

  const listeners = createFunctionComparisonPanelListeners({ emit })

  return {
    currentDataType,
    listeners,
  }
}
