import type { setupParameterValueEditorBindings } from './setup'

interface CreateParameterValueEditorExposedBindingsOptions {
  setupResult: ReturnType<typeof setupParameterValueEditorBindings>
}

export function createParameterValueEditorExposedBindings(
  options: CreateParameterValueEditorExposedBindingsOptions,
) {
  const { state, listeners, panelProps } = options.setupResult

  return {
    showValueDataTypeSwitch: state.showValueDataTypeSwitch,
    valueInputSwitchProps: panelProps.valueInputSwitchProps,
    dataTypeSwitchProps: panelProps.dataTypeSwitchProps,
    valueInputSwitchListeners: listeners.valueInputSwitchListeners,
    dataTypeSwitchListeners: listeners.dataTypeSwitchListeners,
  }
}
