import type { NodeValue } from '../../../../../infrastructure/engine/types'
import type {
  ParameterTypePayload,
  ParameterValuePayload,
  ParameterValueTypePayload,
  ValueDataTypePayload,
} from '../../../../types/nodeEditorPayloads'
import type { ConditionNodeViewEmits } from './types'

export function createConditionNodeViewListeners(emit: ConditionNodeViewEmits) {
  const modeSwitchListeners = {
    'update:negation': (value: boolean) => emit('update:negation', value),
    'switch:mode': (mode: 'condition' | 'function') => emit('switch:mode', mode),
  } as const

  const fieldModeListeners = {
    'update:field': (value: string) => emit('update:field', value),
    'update:array-index': (value: number | undefined) => emit('update:array-index', value),
    'update:comparison': (value: string) => emit('update:comparison', value),
    'update:value': (value: NodeValue) => emit('update:value', value),
    'update:extra-comparison': (value: string | undefined) => emit('update:extra-comparison', value),
    'update:value-data-type': (data: ValueDataTypePayload) => emit('update:value-data-type', data),
  } as const

  const functionModeListeners = {
    'update:function': (value: string) => emit('update:function', value),
    'update:parameter': (data: ParameterValuePayload) => emit('update:parameter', data),
    'update:parameter-type': (data: ParameterTypePayload) => emit('update:parameter-type', data),
    'update:parameter-value-type': (data: ParameterValueTypePayload) => emit('update:parameter-value-type', data),
    'update:comparison': (value: string) => emit('update:comparison', value),
    'update:value': (value: NodeValue) => emit('update:value', value),
    'update:value-data-type': (data: ValueDataTypePayload) => emit('update:function-value-data-type', data),
  } as const

  return {
    modeSwitchListeners,
    fieldModeListeners,
    functionModeListeners,
  }
}
