import { createFunctionModeEditorExposedBindings } from './function-mode-editor-bindings/exposed'
import { setupFunctionModeEditorBindings } from './function-mode-editor-bindings/setup'
import type { UseFunctionModeEditorBindingsOptions } from './function-mode-editor-bindings/types'

export type {
  FunctionModeEditorEmits,
  UseFunctionModeEditorBindingsOptions,
} from './function-mode-editor-bindings/types'

export function useFunctionModeEditorBindings(options: UseFunctionModeEditorBindingsOptions) {
  const setupResult = setupFunctionModeEditorBindings(options)
  return createFunctionModeEditorExposedBindings({ setupResult })
}
