import type { setupFunctionRefParameterInputBodyBindings } from './input-body.setup'

interface CreateFunctionRefParameterInputBodyExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionRefParameterInputBodyBindings>
}

export function createFunctionRefParameterInputBodyExposedBindings(
  options: CreateFunctionRefParameterInputBodyExposedBindingsOptions,
) {
  const { state, listeners } = options.setupResult

  return {
    updateValueListeners: listeners.updateValueListeners,
    displayDescription: state.displayDescription,
    fieldPlaceholder: state.fieldPlaceholder,
    textPlaceholder: state.textPlaceholder,
    isFieldType: state.isFieldType,
    isValueType: state.isValueType,
  }
}
