import type { UseFieldModeControlsBindingsOptions } from './types'

export function createFieldModeControlsListeners(options: UseFieldModeControlsBindingsOptions) {
  const { emit } = options

  const fieldSelectListeners = {
    'update:field': (value: string) => emit('update:field', value),
  } as const

  const arrayIndexListeners = {
    'update:array-index': (value: number | undefined) => emit('update:array-index', value),
  } as const

  const comparisonSelectListeners = {
    'update:comparison': (value: string) => emit('update:comparison', value),
  } as const

  return {
    fieldSelectListeners,
    arrayIndexListeners,
    comparisonSelectListeners,
  }
}
