import type {
  UseValueInputControllerActionsOptions,
  ValueInputControllerState,
} from './useValueInputController.shared'
import { cacheCurrentValueByType } from './useValueInputController.typeActions.cache'
import { resolveRestoredValueByType } from './useValueInputController.typeActions.restore'

export function useValueInputControllerTypeActions(
  state: ValueInputControllerState,
  options: UseValueInputControllerActionsOptions,
) {
  const { emitUpdateValue, emitUpdateType } = options

  const changeValueType = (type: string) => {
    cacheCurrentValueByType(state, options)
    state.userSelectedType.value = type
    emitUpdateType(type)
    emitUpdateValue(resolveRestoredValueByType(type, state, options))
  }

  return {
    changeValueType,
  }
}
