import { createConditionTreeEditorExposedBindings } from './condition-tree-bindings/exposed'
import { setupConditionTreeEditorBindings } from './condition-tree-bindings/setup'
import type { ConditionTreeEditorEmits } from './condition-tree-bindings/types'

export type { ConditionTreeEditorEmits } from './condition-tree-bindings/types'

interface UseConditionTreeEditorBindingsOptions {
  emit: ConditionTreeEditorEmits
}

export function useConditionTreeEditorBindings(options: UseConditionTreeEditorBindingsOptions) {
  const setupResult = setupConditionTreeEditorBindings(options)
  return createConditionTreeEditorExposedBindings({ setupResult })
}
