import type { NodeValue } from '../../../infrastructure/engine/types'

const DEFAULT_VALUE_DATA_TYPE = 'string'
const DEFAULT_VALUE_DATA_TYPE_FIELD = 'condition_value'

export function resolveValueDataType(currentDataType?: string): string {
  if (currentDataType) {
    return currentDataType
  }

  return DEFAULT_VALUE_DATA_TYPE
}

export function resolveValueDataTypeFieldName(fieldName?: string): string {
  if (fieldName) {
    return fieldName
  }

  return DEFAULT_VALUE_DATA_TYPE_FIELD
}

export function toDateValue(value: NodeValue): Date | undefined {
  if (!value) return undefined
  if (typeof value !== 'string' && typeof value !== 'number' && !(value instanceof Date)) {
    return undefined
  }

  const date = new Date(value)
  if (Number.isNaN(date.getTime())) {
    return undefined
  }

  return date
}

export function toMultiValues(value: NodeValue): string[] {
  if (Array.isArray(value)) {
    return value.map((item) => String(item)).filter((item) => item !== '')
  }

  if (typeof value === 'string') {
    return value
      .split(',')
      .map((item) => item.trim())
      .filter((item) => item)
  }

  return []
}
