import {
  copyNode,
  dragNode,
  moveNodeDown,
  moveNodeUp,
} from '../../infrastructure/engine/operations/tree-node'
import type { TreeDragPosition } from '../types/treeInteraction'
import type { TreeExpressionBuilderNotifier } from './treeExpressionBuilderNotifier'
import type { TreeExpressionBuilderState } from './useTreeExpressionBuilderNodeActions.shared'

interface ReorderActionsOptions {
  state: TreeExpressionBuilderState
  commitNodeMutation: (options?: { validate?: boolean }) => void
  notifyDragFailure: (reason?: string) => void
  notifier: TreeExpressionBuilderNotifier
}

export function createTreeExpressionBuilderReorderActions(options: ReorderActionsOptions) {
  const { state, commitNodeMutation, notifyDragFailure, notifier } = options

  const moveNodeUpAction = (nodeId: string) => {
    if (!moveNodeUp(state.rootNodes.value, nodeId)) return
    commitNodeMutation()
  }

  const moveNodeDownAction = (nodeId: string) => {
    if (!moveNodeDown(state.rootNodes.value, nodeId)) return
    commitNodeMutation()
  }

  const copyNodeAction = (nodeId: string) => {
    const result = copyNode(state.rootNodes.value, nodeId, state.parameterDataTypes)
    if (!result.success) return

    commitNodeMutation({ validate: true })
    notifier.success('节点已复制')
  }

  const handleDragNode = (sourceNodeId: string, targetNodeId: string, position: TreeDragPosition) => {
    const result = dragNode(state.rootNodes.value, sourceNodeId, targetNodeId, position)
    if (!result.success) {
      notifyDragFailure(result.reason)
      return
    }

    commitNodeMutation()
    notifier.success('节点移动成功')
  }

  return {
    moveNodeUpAction,
    moveNodeDownAction,
    copyNodeAction,
    handleDragNode,
  }
}
