import { createFieldRefEditorExposedBindings } from './field-ref-bindings/exposed'
import { setupFieldRefEditorBindings } from './field-ref-bindings/setup'
import type { FieldRefEditorProps } from './field-ref-bindings/types'

export type { FieldRefEditorProps } from './field-ref-bindings/types'

export interface FieldRefEditorEmits {
  (e: 'update:field', value: string): void
  (e: 'update:array-index', value: number | undefined): void
}

interface UseFieldRefEditorBindingsOptions {
  props: FieldRefEditorProps
  emit: FieldRefEditorEmits
}

export function useFieldRefEditorBindings(options: UseFieldRefEditorBindingsOptions) {
  const setupResult = setupFieldRefEditorBindings({
    props: options.props,
    emitUpdateField: (value) => options.emit('update:field', value),
  })

  return createFieldRefEditorExposedBindings({ setupResult })
}
