import { ref } from 'vue'
import type { TreeExpressionBuilderCoreOptions, TreeExpressionBuilderValidationRefs } from './useTreeExpressionBuilderState.shared'

interface ExpressionStateOptions extends TreeExpressionBuilderCoreOptions {
  emitUpdateModelValue: (value: string) => void
  syncServiceFields: () => void
  runValidation: () => void
  validationRefs: TreeExpressionBuilderValidationRefs
}

export function useTreeExpressionBuilderExpressionState(options: ExpressionStateOptions) {
  const {
    service,
    rootNodes,
    emitUpdateModelValue,
    syncServiceFields,
    runValidation,
    validationRefs,
  } = options

  const {
    parseError,
    validationErrors,
    validationResult,
  } = validationRefs

  const generatedExpression = ref('')

  const emitExpression = (expression: string) => {
    generatedExpression.value = expression
    emitUpdateModelValue(expression)
  }

  const regenerateExpression = () => {
    syncServiceFields()
    const expression = service.generate(rootNodes.value)
    emitExpression(expression)
  }

  const resetForEmptyExpression = () => {
    rootNodes.value = []
    generatedExpression.value = ''
    parseError.value = null
    validationErrors.value = []
    validationResult.value = null
  }

  const loadExpression = (expression: string) => {
    syncServiceFields()
    service.clearParameterDataTypes()

    if (!expression || !expression.trim()) {
      resetForEmptyExpression()
      return
    }

    const result = service.parseDetailed(expression)
    generatedExpression.value = expression

    if (result.success) {
      rootNodes.value = result.nodes
      parseError.value = null
      runValidation()
      return
    }

    rootNodes.value = []
    validationErrors.value = []
    parseError.value = result.error || '表达式解析失败'
  }

  return {
    generatedExpression,
    emitExpression,
    regenerateExpression,
    loadExpression,
  }
}
