import { createValueInputPanelBodyEventListeners } from '../panel-body-listeners.shared'
import type { ValueInputPanelBodyForwarders } from '../panel-body-listeners.shared'
import { createValueInputPanelFieldRefListeners } from './listeners.field'
import { createValueInputPanelFunctionRefListeners } from './listeners.function'
import { createValueInputPanelValueEditorListeners } from './listeners.value'

export function createValueInputPanelBodyListeners(forwarders: ValueInputPanelBodyForwarders) {
  const panelBodyListeners = createValueInputPanelBodyEventListeners(forwarders)

  const valueEditorListeners = createValueInputPanelValueEditorListeners(panelBodyListeners)
  const fieldRefListeners = createValueInputPanelFieldRefListeners(panelBodyListeners)
  const functionRefListeners = createValueInputPanelFunctionRefListeners(panelBodyListeners)

  return {
    valueEditorListeners,
    fieldRefListeners,
    functionRefListeners,
  }
}
