import { createFunctionComparisonPanelExposedBindings } from './function-comparison-panel-bindings/exposed'
import { setupFunctionComparisonPanelBindings } from './function-comparison-panel-bindings/setup'
import type {
  UseFunctionComparisonPanelBindingsOptions,
} from './function-comparison-panel-bindings/types'

export type {
  FunctionComparisonPanelEmits,
  FunctionComparisonPanelProps,
  UseFunctionComparisonPanelBindingsOptions,
} from './function-comparison-panel-bindings/types'

export function useFunctionComparisonPanelBindings(options: UseFunctionComparisonPanelBindingsOptions) {
  const setupResult = setupFunctionComparisonPanelBindings(options)
  return createFunctionComparisonPanelExposedBindings({ setupResult })
}
