import type { TreeNode } from '../../../../infrastructure/engine/types'
import type { BuilderNodeType, TreeDragPosition } from '../../../types/treeInteraction'
import type { UseParameterInputBindingsOptions } from './types'

interface CreateParameterInputConditionModeListenersOptions {
  emit: UseParameterInputBindingsOptions['emit']
  updateNestedNode: (nodeId: string, updates: Partial<TreeNode>) => void
  updateNestedParameterType: (paramName: string, type: string) => void
}

export function createParameterInputConditionModeListeners(
  options: CreateParameterInputConditionModeListenersOptions,
) {
  const { emit, updateNestedNode, updateNestedParameterType } = options

  const conditionModeListeners = {
    'update-node': updateNestedNode,
    'add-child': (parentId: string, nodeType: BuilderNodeType) => emit('add-child', parentId, nodeType),
    'remove-node': (nodeId: string) => emit('remove-node', nodeId),
    'move-up': (nodeId: string) => emit('move-up', nodeId),
    'move-down': (nodeId: string) => emit('move-down', nodeId),
    'copy-node': (nodeId: string) => emit('copy-node', nodeId),
    'update-parameter-type': updateNestedParameterType,
    'update-parameter-value-data-type': (nodeId: string, paramName: string, dataType: string) => {
      emit('update-parameter-value-data-type', nodeId, paramName, dataType)
    },
    'drag-node': (sourceId: string, targetId: string, position: TreeDragPosition) => {
      emit('drag-node', sourceId, targetId, position)
    },
  }

  return {
    conditionModeListeners,
  }
}
