import { computed } from 'vue'
import type { ParameterValueEditorProps } from './types'

export function createParameterValueEditorState(props: ParameterValueEditorProps) {
  const resolvedDisplayValue = computed(() => {
    if (props.displayValue !== undefined) {
      return props.displayValue
    }
    return props.value
  })

  const isFormatParameter = computed(() => props.parameterName === 'format')
  const isTimezoneParameter = computed(() => props.parameterName === 'timezone')

  const isMultiValue = computed(() => {
    return props.parameterName === 'items'
      || (props.parameterDescription || '').includes('多个')
      || (props.parameterDescription || '').includes('列表')
  })

  const multiValuePlaceholder = computed(() => {
    return `输入${props.parameterDescription}，回车分隔`
  })

  const showValueDataTypeSwitch = computed(() => {
    return props.showDataTypeSwitch && props.parameterType !== 'field'
  })

  return {
    resolvedDisplayValue,
    isFormatParameter,
    isTimezoneParameter,
    isMultiValue,
    multiValuePlaceholder,
    showValueDataTypeSwitch,
  }
}
