import { computed, unref } from 'vue'
import type { ParameterInputProps } from '../../../composables/useParameterInputController'
import type {
  ParameterInputViewModelController,
  ParameterInputViewModelState,
} from './view-model.types'

interface CreateParameterInputModePropsOptions {
  props: ParameterInputProps
  controller: ParameterInputViewModelController
  state: ParameterInputViewModelState
}

export function createParameterInputModeProps(options: CreateParameterInputModePropsOptions) {
  const { props, controller, state } = options

  const valueModeProps = computed(() => ({
    parameter: props.parameter,
    value: props.value,
    displayValue: unref(controller.displayValue),
    availableFields: props.availableFields,
    valueDataType: controller.getValueDataType(),
    multiValues: controller.getMultiValue(),
    getTypeColor: controller.getTypeColor,
  }))

  const fieldModeProps = computed(() => ({
    displayValue: unref(controller.displayValue),
    availableFields: props.availableFields,
    getFieldTooltipText: controller.getFieldTooltipText,
    getTypeColor: controller.getTypeColor,
  }))

  const conditionModeProps = computed(() => ({
    node: state.conditionNode.value,
    availableFields: props.availableFields,
    expectedReturnType: props.currentDataType || props.parameter.valueType,
    getParameterDataType: props.getParameterDataType,
  }))

  const lambdaModeProps = computed(() => ({
    value: unref(controller.displayValue),
  }))

  return {
    valueModeProps,
    fieldModeProps,
    conditionModeProps,
    lambdaModeProps,
  }
}
