import type { UseFunctionSelectPanelBindingsOptions } from './types'

export function setupFunctionSelectPanelBindings(options: UseFunctionSelectPanelBindingsOptions) {
  const onUpdateFunction = (value: string) => options.emit('update:function', value)
  const onShowUsage = () => options.emit('show-usage')

  return {
    onUpdateFunction,
    onShowUsage,
  }
}
