      <icon-up />
    </a-button>
  </a-tooltip>

  <a-tooltip content="下移节点">
    <a-button type="text" size="mini" @click="emit('move-down', nodeId)">
      <icon-down />
    </a-button>
  </a-tooltip>

  <a-tooltip content="复制节点">
    <a-button type="text" size="mini" @click="emit('copy-node', nodeId)">
      <icon-copy />
    </a-button>
  </a-tooltip>

  <a-tooltip content="删除节点">
    <a-button type="text" size="mini" status="danger" @click="emit('remove-node', nodeId)">
      <icon-delete />
    </a-button>
  </a-tooltip>
</template>

<script setup lang="ts">
defineProps<{
  nodeId: string
}>()

const emit = defineEmits<{
  (e: 'move-up', nodeId: string): void
  (e: 'move-down', nodeId: string): void
  (e: 'copy-node', nodeId: string): void
  (e: 'remove-node', nodeId: string): void
