import { useParameterInputControllerActions } from './useParameterInputController.actions'
import { buildParameterInputControllerExposed } from './useParameterInputController.exposed'
import { useParameterInputControllerState } from './useParameterInputController.state'
import type { UseParameterInputControllerOptions } from './useParameterInputController.types'
import { registerParameterInputControllerWatchers } from './useParameterInputController.watchers'

export type {
  ParameterInputProps,
  UseParameterInputControllerOptions,
} from './useParameterInputController.types'

export function useParameterInputController(options: UseParameterInputControllerOptions) {
  const state = useParameterInputControllerState({ props: options.props })

  const actions = useParameterInputControllerActions(state, {
    props: options.props,
    emitUpdateValue: options.emitUpdateValue,
    emitUpdateType: options.emitUpdateType,
    emitUpdateValueDataType: options.emitUpdateValueDataType,
  })

  registerParameterInputControllerWatchers({
    props: options.props,
    state,
    actions,
  })

  return buildParameterInputControllerExposed(state, actions)
}
