import { createFunctionCatalogSelectExposedBindings } from './function-catalog-select-bindings/exposed'
import { setupFunctionCatalogSelectBindings } from './function-catalog-select-bindings/setup'
import type {
  UseFunctionCatalogSelectBindingsOptions,
} from './function-catalog-select-bindings/types'

export type {
  FunctionCatalogSelectEmits,
  FunctionCatalogSelectProps,
  UseFunctionCatalogSelectBindingsOptions,
} from './function-catalog-select-bindings/types'

export function useFunctionCatalogSelectBindings(options: UseFunctionCatalogSelectBindingsOptions) {
  const setupResult = setupFunctionCatalogSelectBindings(options)
  return createFunctionCatalogSelectExposedBindings({ setupResult })
}
