import type { useFunctionModeEditorControllerActions } from './useFunctionModeEditorController.actions'
import type { useFunctionModeEditorControllerState } from './useFunctionModeEditorController.state'

interface CreateFunctionModeEditorControllerExposedOptions {
  state: ReturnType<typeof useFunctionModeEditorControllerState>
  actions: ReturnType<typeof useFunctionModeEditorControllerActions>
}

export function createFunctionModeEditorControllerExposed(
  options: CreateFunctionModeEditorControllerExposedOptions,
) {
  const { state, actions } = options

  return {
    selectedFunction: state.selectedFunction,
    functionCategories: state.functionCategories,
    shouldShowComparison: state.shouldShowComparison,
    returnTypeOperators: state.returnTypeOperators,
    getParameterActualValue: state.getParameterActualValue,
    getParameterWithValue: state.getParameterWithValue,
    filterFunctionOption: actions.filterFunctionOption,
    showFunctionUsage: actions.showFunctionUsage,
  }
}
