import type { TreeExpressionBuilderBindingsController } from './types'

export function createTreeExpressionBuilderToolbarListeners(
  controller: TreeExpressionBuilderBindingsController,
) {
  return {
    'add-group': controller.addGroup,
    'expand-all': controller.expandAll,
    'collapse-all': controller.collapseAll,
  } as const
}
