import { createParameterValueEditorForwarders } from './forwarders'
import { createParameterValueEditorListeners } from './listeners'
import { createParameterValueEditorPanelProps } from './panelProps'
import { createParameterValueEditorState } from './state'
import type { ParameterValueEditorEmits, ParameterValueEditorProps } from './types'

interface SetupParameterValueEditorBindingsOptions {
  props: ParameterValueEditorProps
  emit: ParameterValueEditorEmits
}

export function setupParameterValueEditorBindings(options: SetupParameterValueEditorBindingsOptions) {
  const { props, emit } = options

  const state = createParameterValueEditorState(props)
  const forwarders = createParameterValueEditorForwarders(emit)
  const listeners = createParameterValueEditorListeners({ forwarders })
  const panelProps = createParameterValueEditorPanelProps(props, state)

  return {
    state,
    listeners,
    panelProps,
  }
}
