import type { UseAviatorExpressionBuilderBindingsOptions } from './types'

export function setupAviatorExpressionBuilderBindings(options: UseAviatorExpressionBuilderBindingsOptions) {
  const onUpdateModelValue = (value: string) => {
    options.emit('update:modelValue', value)
  }

  return {
    onUpdateModelValue,
  }
}
