interface CreateAviatorExpressionBuilderModalListenersOptions {
  handleSave: () => void
  handleCancel: () => void
}

export function createAviatorExpressionBuilderModalListeners(
  options: CreateAviatorExpressionBuilderModalListenersOptions,
) {
  const { handleSave, handleCancel } = options

  const modalListeners = {
    ok: () => handleSave(),
    cancel: () => handleCancel(),
  } as const

  const footerListeners = {
    save: () => handleSave(),
    cancel: () => handleCancel(),
  } as const

  return {
    modalListeners,
    footerListeners,
  }
}
