import type { AviatorFunction } from '../../../infrastructure/engine/types'
import { findFunctionByName, parseFunctionNameFromExpression } from '../../logic/value-input'
import type { FunctionRefParameter } from './types'

export function createFunctionParameters(func: AviatorFunction): FunctionRefParameter[] {
  return func.parameters.map((param) => ({
    ...param,
    value: undefined,
    type: 'value',
  }))
}

export function findFunctionByExpression(
  expression: unknown,
  functions: readonly AviatorFunction[],
): AviatorFunction | null {
  const functionName = parseFunctionNameFromExpression(expression)
  return findFunctionByName(functionName, functions)
}
