import type { NodeValue } from '../../infrastructure/engine/types'
import type {
  UseValueInputControllerActionsOptions,
  ValueInputControllerState,
} from './useValueInputController.shared'

function restoreValueModeValue(state: ValueInputControllerState): string | number | boolean {
  let valueToRestore: string | number | boolean = state.savedStringValue.value || ''
  const currentDataType = state.getValueDataType()

  if (currentDataType === 'number') {
    if (valueToRestore && !Number.isNaN(Number(valueToRestore)) && String(valueToRestore).trim() !== '') {
      valueToRestore = Number(valueToRestore)
    }
    return valueToRestore
  }

  if (currentDataType === 'string') {
    return String(valueToRestore)
  }

  const text = String(valueToRestore)
  if (text && !Number.isNaN(Number(text)) && text.trim() !== '') {
    return Number(text)
  }
  if (text === 'true' || text === 'false') {
    return text === 'true'
  }
  return valueToRestore
}

function restoreFieldModeValue(
  state: ValueInputControllerState,
  options: UseValueInputControllerActionsOptions,
): string {
  const { availableFields } = options.props
  let fieldValue = state.savedFieldValue.value
  if (!fieldValue || !availableFields?.some((field) => field.value === fieldValue)) {
    fieldValue = availableFields?.length ? availableFields[0].value : ''
  }
  return fieldValue
}

function restoreFunctionModeValue(
  state: ValueInputControllerState,
  options: UseValueInputControllerActionsOptions,
): NodeValue {
  let functionValue = state.savedFunctionValue.value || options.props.value

  if (!state.functionRefController.initializeFromExpression(functionValue)) {
    functionValue = 'string.length(field_name)'
    state.functionRefController.initializeFromExpression(functionValue)
  }

  return functionValue
}

export function resolveRestoredValueByType(
  type: string,
  state: ValueInputControllerState,
  options: UseValueInputControllerActionsOptions,
): NodeValue {
  if (type === 'value') {
    return restoreValueModeValue(state)
  }

  if (type === 'field') {
    return restoreFieldModeValue(state, options)
  }

  return restoreFunctionModeValue(state, options)
}
