import { createConditionModeSwitchExposedBindings } from './condition-mode-switch-bindings/exposed'
import { setupConditionModeSwitchBindings } from './condition-mode-switch-bindings/setup'
import type {
  UseConditionModeSwitchBindingsOptions,
} from './condition-mode-switch-bindings/types'

export type {
  ConditionModeSwitchEmits,
  ConditionModeSwitchProps,
  UseConditionModeSwitchBindingsOptions,
} from './condition-mode-switch-bindings/types'

export function useConditionModeSwitchBindings(options: UseConditionModeSwitchBindingsOptions) {
  const setupResult = setupConditionModeSwitchBindings(options)
  return createConditionModeSwitchExposedBindings({ setupResult })
}
