import { AVIATOR_FUNCTIONS } from '../../infrastructure/engine/constants'

const getFunctionNameFromOption = (optionData: unknown): string => {
  if (!optionData || typeof optionData !== 'object') return ''

  const optionRecord = optionData as Record<string, unknown>
  const candidate = optionRecord.value || optionRecord.key
  return typeof candidate === 'string' ? candidate : ''
}

export function useFunctionModeEditorControllerFilterActions() {
  const filterFunctionOption = (inputValue: string, optionData: unknown) => {
    if (!inputValue) return true

    const searchText = inputValue.toLowerCase()
    const functionName = getFunctionNameFromOption(optionData)
    const func = AVIATOR_FUNCTIONS.find((item) => item.name === functionName)
    if (!func) return false

    return func.name.toLowerCase().includes(searchText)
      || func.displayName.toLowerCase().includes(searchText)
      || func.description.toLowerCase().includes(searchText)
  }

  return {
    filterFunctionOption,
  }
}
