import type { useValueInputControllerFieldActions } from './useValueInputController.fieldActions'
import type { useValueInputControllerFunctionActions } from './useValueInputController.functionActions'
import type { useValueInputControllerTypeActions } from './useValueInputController.typeActions'
import type { useValueInputControllerValueActions } from './useValueInputController.valueActions'

interface CreateValueInputControllerActionsExposedOptions {
  valueActions: ReturnType<typeof useValueInputControllerValueActions>
  typeActions: ReturnType<typeof useValueInputControllerTypeActions>
  fieldActions: ReturnType<typeof useValueInputControllerFieldActions>
  functionActions: ReturnType<typeof useValueInputControllerFunctionActions>
}

export function createValueInputControllerActionsExposed(
  options: CreateValueInputControllerActionsExposedOptions,
) {
  const { valueActions, typeActions, fieldActions, functionActions } = options

  return {
    updateValue: valueActions.updateValue,
    updateMultiValues: valueActions.updateMultiValues,
    updateDateValue: valueActions.updateDateValue,
    validateURL: valueActions.validateURL,
    changeValueDataType: valueActions.changeValueDataType,
    changeValueType: typeActions.changeValueType,
    updateBaseField: fieldActions.updateBaseField,
    updateValueArrayIndex: fieldActions.updateValueArrayIndex,
    updateFunction: functionActions.updateFunction,
    updateParameter: functionActions.updateParameter,
    generateFunctionExpression: functionActions.generateFunctionExpression,
  }
}
