import { useValueInputController } from '../../../composables/useValueInputController'
import { createValueInputViewListeners } from './listeners'
import { createValueInputSwitchPanelProps } from './panelProps'
import { createValueInputViewState } from './state'
import type { UseValueInputViewBindingsOptions } from './types'

export function setupValueInputViewBindings(options: UseValueInputViewBindingsOptions) {
  const controller = useValueInputController({
    props: options.props,
    emitUpdateValue: options.emitUpdateValue,
    emitUpdateType: options.emitUpdateType,
    emitUpdateValueDataType: options.emitUpdateValueDataType,
  })

  const viewState = createValueInputViewState({ controller })
  const listeners = createValueInputViewListeners({
    changeValueType: controller.changeValueType,
    updateValue: controller.updateValue,
    updateMultiValues: controller.updateMultiValues,
    updateDateValue: controller.updateDateValue,
    validateURL: controller.validateURL,
    changeValueDataType: controller.changeValueDataType,
    updateBaseField: controller.updateBaseField,
    updateValueArrayIndex: controller.updateValueArrayIndex,
    updateFunction: controller.updateFunction,
    onUpdateParameter: viewState.onUpdateParameter,
  })
  const switchPanelProps = createValueInputSwitchPanelProps({
    props: options.props,
    controller,
    state: viewState,
  })

  return {
    isCompoundOperator: controller.isCompoundOperator,
    listeners,
    switchPanelProps,
  }
}
