import { createConditionModeRadioExposedBindings } from './condition-mode-radio-bindings/exposed'
import { setupConditionModeRadioBindings } from './condition-mode-radio-bindings/setup'
import type {
  UseConditionModeRadioBindingsOptions,
} from './condition-mode-radio-bindings/types'

export type {
  ConditionModeRadioEmits,
  ConditionModeRadioProps,
  UseConditionModeRadioBindingsOptions,
} from './condition-mode-radio-bindings/types'

export function useConditionModeRadioBindings(options: UseConditionModeRadioBindingsOptions) {
  const setupResult = setupConditionModeRadioBindings(options)
  return createConditionModeRadioExposedBindings({ setupResult })
}
