import type { setupNodeActionsBindings } from './setup'

interface CreateNodeActionsExposedBindingsOptions {
  setupResult: ReturnType<typeof setupNodeActionsBindings>
}

export function createNodeActionsExposedBindings(options: CreateNodeActionsExposedBindingsOptions) {
  const { setupResult } = options

  return {
    groupAddListeners: setupResult.listeners.groupAddListeners,
    commonButtonListeners: setupResult.listeners.commonButtonListeners,
  }
}
