import type { createTreeNodeDragLeaveHandler } from './leave'
import type { createTreeNodeDragOverDropHandlers } from './over-drop'
import type { createTreeNodeDragStartEndHandlers } from './start-end'

interface CreateTreeNodeDragHandlersExposedOptions {
  startEndHandlers: ReturnType<typeof createTreeNodeDragStartEndHandlers>
  overDropHandlers: ReturnType<typeof createTreeNodeDragOverDropHandlers>
  leaveHandler: ReturnType<typeof createTreeNodeDragLeaveHandler>
}

export function createTreeNodeDragHandlersExposed(
  options: CreateTreeNodeDragHandlersExposedOptions,
) {
  const { startEndHandlers, overDropHandlers, leaveHandler } = options

  return {
    handleDragStart: startEndHandlers.handleDragStart,
    handleDragEnd: startEndHandlers.handleDragEnd,
    handleDragOver: overDropHandlers.handleDragOver,
    handleDrop: overDropHandlers.handleDrop,
    handleDragLeave: leaveHandler.handleDragLeave,
  }
}
