import { createFunctionRefParameterInputForwarders } from './forwarders'
import { createFunctionRefParameterItemListeners } from './item.listeners'
import { createFunctionRefParameterItemPanelProps } from './item.panel-props'
import type { UseFunctionRefParameterItemBindingsOptions } from './item.types'

export function setupFunctionRefParameterItemBindings(options: UseFunctionRefParameterItemBindingsOptions) {
  const forwarders = createFunctionRefParameterInputForwarders(options.emit)
  const listeners = createFunctionRefParameterItemListeners({
    props: options.props,
    forwarders,
  })
  const panelProps = createFunctionRefParameterItemPanelProps(options.props)

  return {
    listeners,
    panelProps,
  }
}
