import type { setupFunctionParameterItemBindings } from './setup'

interface CreateFunctionParameterItemExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionParameterItemBindings>
}

export function createFunctionParameterItemExposedBindings(
  options: CreateFunctionParameterItemExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    parameterInputListeners: setupResult.listeners.parameterInputListeners,
  }
}
