import type { setupValueInputPanelBodyBindings } from './setup'

interface CreateValueInputPanelBodyExposedBindingsOptions {
  setupResult: ReturnType<typeof setupValueInputPanelBodyBindings>
}

export function createValueInputPanelBodyExposedBindings(
  options: CreateValueInputPanelBodyExposedBindingsOptions,
) {
  const { state, panelProps, listeners } = options.setupResult

  return {
    isValueMode: state.isValueMode,
    isFieldMode: state.isFieldMode,
    isFunctionMode: state.isFunctionMode,
    valueEditorProps: panelProps.valueEditorProps,
    fieldRefEditorProps: panelProps.fieldRefEditorProps,
    functionRefEditorProps: panelProps.functionRefEditorProps,
    valueEditorListeners: listeners.valueEditorListeners,
    fieldRefListeners: listeners.fieldRefListeners,
    functionRefListeners: listeners.functionRefListeners,
  }
}
