<template>
  <ConditionValueEditor
    v-if="isConditionMode"
    v-bind="conditionEditorProps"
    v-on="conditionEditorListeners"
  />

  <ParameterValueEditor
    v-else
    v-bind="parameterEditorProps"
    v-on="parameterEditorListeners"
  />
</template>

<script setup lang="ts">
import ConditionValueEditor from './ConditionValueEditor.vue'
import ParameterValueEditor from './ParameterValueEditor.vue'
import {
  type ValueEditorEmits,
  type ValueEditorProps,
  useValueEditorBindings,
} from './useValueEditorBindings'

const props = withDefaults(defineProps<ValueEditorProps>(), {
  mode: 'condition',
  placeholder: '输入值',
  multiValues: () => [],
  parameterDescription: '参数值',
  showDataTypeSwitch: true,
})

const emit = defineEmits<ValueEditorEmits>()

const {
  isConditionMode,
  conditionEditorProps,
  parameterEditorProps,
  conditionEditorListeners,
  parameterEditorListeners,
} = useValueEditorBindings({
  props,
  emit,
})
</script>
