import type { createTreeNodeContentActionBindings } from './actions'
import type { createTreeNodeContentDragBindings } from './drag'
import type { createTreeNodeContentEditorBindings } from './editor'

interface CreateTreeNodeContentListenersOptions {
  dragBindings: ReturnType<typeof createTreeNodeContentDragBindings>
  editorBindings: ReturnType<typeof createTreeNodeContentEditorBindings>
  actionBindings: ReturnType<typeof createTreeNodeContentActionBindings>
}

export function createTreeNodeContentListeners(options: CreateTreeNodeContentListenersOptions) {
  const { dragBindings, editorBindings, actionBindings } = options

  const affordanceListeners = {
    'toggle-expanded': dragBindings.onToggleExpanded,
  }

  const editorListeners = {
    'update:condition-negation': editorBindings.onConditionNegation,
    'switch:mode': editorBindings.onSwitchMode,
    'update:field': editorBindings.onUpdateField,
    'update:array-index': editorBindings.onUpdateArrayIndex,
    'update:comparison': editorBindings.onUpdateComparison,
    'update:value': editorBindings.onUpdateValue,
    'update:extra-comparison': editorBindings.onUpdateExtraComparison,
    'update:value-data-type': editorBindings.onUpdateValueDataType,
    'update:function': editorBindings.onUpdateFunction,
    'update:parameter': editorBindings.onUpdateParameter,
    'update:parameter-type': editorBindings.onUpdateParameterType,
    'update:parameter-value-type': editorBindings.onUpdateParameterValueType,
    'update:function-value-data-type': editorBindings.onUpdateFunctionValueDataType,
    'update:group-operator': editorBindings.onUpdateGroupOperator,
    'update:group-negation': editorBindings.onUpdateGroupNegation,
  }

  const actionListeners = {
    'add-child': actionBindings.onAddChild,
    'move-up': actionBindings.onMoveUp,
    'move-down': actionBindings.onMoveDown,
    'copy-node': actionBindings.onCopyNode,
    'remove-node': actionBindings.onRemoveNode,
  }

  return {
    affordanceListeners,
    editorListeners,
    actionListeners,
  }
}
