import type { setupAviatorExpressionBuilderLegacyModalBindings } from './setup'
import type { AviatorExpressionBuilderLegacyModalExposed } from './types'

interface CreateAviatorExpressionBuilderLegacyModalExposedBindingsOptions {
  setupResult: ReturnType<typeof setupAviatorExpressionBuilderLegacyModalBindings>
}

export function createAviatorExpressionBuilderLegacyModalExposedBindings(
  options: CreateAviatorExpressionBuilderLegacyModalExposedBindingsOptions,
) {
  const {
    visible,
    currentExpression,
    dataPreview,
    fieldOptions,
    handleOk,
    handleCancel,
    open,
    updateFieldOptions,
  } = options.setupResult

  const exposedApi: AviatorExpressionBuilderLegacyModalExposed = {
    open,
    updateFieldOptions,
  }

  return {
    visible,
    currentExpression,
    dataPreview,
    fieldOptions,
    handleOk,
    handleCancel,
    exposedApi,
  }
}
