import type { TreeExpressionBuilderBindingsController } from './types'

export function createTreeExpressionBuilderTreeCanvasListeners(
  controller: TreeExpressionBuilderBindingsController,
) {
  return {
    'update-node': controller.updateNode,
    'add-child': controller.addChildNode,
    'remove-node': controller.removeNode,
    'move-up': controller.moveNodeUpAction,
    'move-down': controller.moveNodeDownAction,
    'copy-node': controller.copyNodeAction,
    'update-parameter-type': controller.handleParameterTypeUpdate,
    'update-parameter-value-data-type': controller.handleParameterValueDataTypeUpdate,
    'drag-node': controller.handleDragNode,
    'add-group': controller.addGroup,
  } as const
}
