import type { createTreeNodeEventForwarders } from './forwarders'

interface CreateTreeNodeListenersOptions {
  forwarders: ReturnType<typeof createTreeNodeEventForwarders>
}

export function createTreeNodeListeners(options: CreateTreeNodeListenersOptions) {
  const { forwarders } = options

  const treeNodeListeners = {
    'update-node': forwarders.onUpdateNode,
    'add-child': forwarders.onAddChild,
    'remove-node': forwarders.onRemoveNode,
    'move-up': forwarders.onMoveUp,
    'move-down': forwarders.onMoveDown,
    'copy-node': forwarders.onCopyNode,
    'update-parameter-type': forwarders.onUpdateParameterType,
    'update-parameter-value-data-type': forwarders.onUpdateParameterValueDataType,
    'drag-node': forwarders.onDragNode,
  } as const

  return {
    treeNodeListeners,
  }
}
