import type { ValueInputSwitchPanelEmits } from './types'
import { createValueFieldForwarders } from './forwarders/field-forwarders'
import { createValueFunctionForwarders } from './forwarders/function-forwarders'
import { createValueTypeForwarders } from './forwarders/type-forwarders'
import { createValueEditForwarders } from './forwarders/value-forwarders'
import { createValueInputForwardersExposed } from './value-input-forwarders.exposed'

export function createValueInputForwarders(emit: ValueInputSwitchPanelEmits) {
  const typeForwarders = createValueTypeForwarders(emit)
  const valueForwarders = createValueEditForwarders(emit)
  const fieldForwarders = createValueFieldForwarders(emit)
  const functionForwarders = createValueFunctionForwarders(emit)

  return createValueInputForwardersExposed({
    typeForwarders,
    valueForwarders,
    fieldForwarders,
    functionForwarders,
  })
}
