import { createValueEditorExposedBindings } from './value-editor-bindings/exposed'
import { setupValueEditorBindings } from './value-editor-bindings/setup'
import type { ValueEditorEmits, ValueEditorProps } from './value-editor-bindings/types'

export type { ValueEditorEmits, ValueEditorProps } from './value-editor-bindings/types'

interface UseValueEditorBindingsOptions {
  props: ValueEditorProps
  emit: ValueEditorEmits
}

export function useValueEditorBindings(options: UseValueEditorBindingsOptions) {
  const setupResult = setupValueEditorBindings(options)
  return createValueEditorExposedBindings({ setupResult })
}
