import type { NodeValue } from '../../../infrastructure/engine/types'
import type {
  ParameterTypePayload,
  ParameterValuePayload,
  ParameterValueTypePayload,
  ValueDataTypePayload,
} from '../../types/nodeEditorPayloads'

interface TreeNodeViewHandlerOptions {
  updateConditionValueDataType: (fieldName: string, dataType: string) => void
  updateFunctionValueDataType: (fieldName: string, dataType: string) => void
  updateParameter: (paramName: string, value: NodeValue) => void
  updateParameterType: (paramName: string, type: string) => void
  updateParameterValueDataType: (paramName: string, dataType: string) => void
}

export function createTreeNodeViewHandlers(options: TreeNodeViewHandlerOptions) {
  const {
    updateConditionValueDataType,
    updateFunctionValueDataType,
    updateParameter,
    updateParameterType,
    updateParameterValueDataType,
  } = options

  const onConditionValueDataType = ({ fieldName, dataType }: ValueDataTypePayload) => {
    updateConditionValueDataType(fieldName, dataType)
  }

  const onFunctionValueDataType = ({ fieldName, dataType }: ValueDataTypePayload) => {
    updateFunctionValueDataType(fieldName, dataType)
  }

  const onParameterUpdate = ({ paramName, value }: ParameterValuePayload) => {
    updateParameter(paramName, value)
  }

  const onParameterTypeUpdate = ({ paramName, type }: ParameterTypePayload) => {
    updateParameterType(paramName, type)
  }

  const onParameterValueTypeUpdate = ({ paramName, dataType }: ParameterValueTypePayload) => {
    updateParameterValueDataType(paramName, dataType)
  }

  return {
    onConditionValueDataType,
    onFunctionValueDataType,
    onParameterUpdate,
    onParameterTypeUpdate,
    onParameterValueTypeUpdate,
  }
}
