import type { setupConditionModeRadioBindings } from './setup'

interface CreateConditionModeRadioExposedBindingsOptions {
  setupResult: ReturnType<typeof setupConditionModeRadioBindings>
}

export function createConditionModeRadioExposedBindings(
  options: CreateConditionModeRadioExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    radioGroupListeners: setupResult.radioGroupListeners,
  }
}
