import type { useTreeExpressionBuilderActions } from './useTreeExpressionBuilderActions'
import type { useTreeExpressionBuilderState } from './useTreeExpressionBuilderState'

interface CreateTreeExpressionBuilderControllerExposedOptions {
  state: ReturnType<typeof useTreeExpressionBuilderState>
  actions: ReturnType<typeof useTreeExpressionBuilderActions>
}

export function createTreeExpressionBuilderControllerExposed(
  options: CreateTreeExpressionBuilderControllerExposedOptions,
) {
  const { state, actions } = options

  return {
    extractedFields: state.extractedFields,
    dataSourceInfo: state.dataSourceInfo,
    rootNodes: state.rootNodes,
    availableFields: state.availableFields,
    validationErrors: state.validationErrors,
    allErrors: state.allErrors,
    generatedExpression: state.generatedExpression,
    validating: state.validating,
    validationResult: state.validationResult,
    addGroup: actions.addGroup,
    expandAll: actions.expandAll,
    collapseAll: actions.collapseAll,
    updateNode: actions.updateNode,
    addChildNode: actions.addChildNode,
    removeNode: actions.removeNode,
    moveNodeUpAction: actions.moveNodeUpAction,
    moveNodeDownAction: actions.moveNodeDownAction,
    copyNodeAction: actions.copyNodeAction,
    handleParameterTypeUpdate: actions.handleParameterTypeUpdate,
    handleParameterValueDataTypeUpdate: actions.handleParameterValueDataTypeUpdate,
    handleDragNode: actions.handleDragNode,
    clearExpression: actions.clearExpression,
    validateExpressionManually: actions.validateExpressionManually,
    copyExpression: actions.copyExpression,
    formatExpression: actions.formatExpression,
    getParameterDataType: actions.getParameterDataType,
  }
}
