import type {
  UseValueInputControllerActionsOptions,
  ValueInputControllerState,
} from './useValueInputController.shared'

export function cacheCurrentValueByType(
  state: ValueInputControllerState,
  options: UseValueInputControllerActionsOptions,
): void {
  const currentType = state.getValueInputType()
  const { value } = options.props

  if (!value) {
    return
  }

  if (currentType === 'value') {
    state.savedStringValue.value = String(value)
  }
  if (currentType === 'field') {
    state.savedFieldValue.value = String(value)
  }
  if (currentType === 'function') {
    state.savedFunctionValue.value = String(value)
  }
}
