<template>
  <ParameterFormatSelect
    v-if="props.isFormatParameter"
    v-bind="formatSelectProps"
    v-on="valueListeners"
  />

  <ParameterTimezoneSelect
    v-else-if="props.isTimezoneParameter"
    v-bind="timezoneSelectProps"
    v-on="valueListeners"
  />

  <ParameterMultiValueInput
    v-else-if="props.isMultiValue"
    v-bind="multiValueInputProps"
    v-on="multiValueListeners"
  />

  <ParameterValueFallbackInput
    v-else
    v-bind="fallbackInputProps"
    v-on="fallbackListeners"
  />
</template>

<script setup lang="ts">
import ParameterFormatSelect from './ParameterFormatSelect.vue'
import ParameterMultiValueInput from './ParameterMultiValueInput.vue'
import ParameterTimezoneSelect from './ParameterTimezoneSelect.vue'
import ParameterValueFallbackInput from './switch/ParameterValueFallbackInput.vue'
import {
  type ParameterValueInputSwitchEmits,
  type ParameterValueInputSwitchProps,
  useParameterValueInputSwitchBindings,
} from './switch/useParameterValueInputSwitchBindings'

const props = defineProps<ParameterValueInputSwitchProps>()

const emit = defineEmits<ParameterValueInputSwitchEmits>()

const {
  formatSelectProps,
  timezoneSelectProps,
  multiValueInputProps,
  fallbackInputProps,
  valueListeners,
  multiValueListeners,
  fallbackListeners,
} = useParameterValueInputSwitchBindings({
  props,
  emit,
})
</script>
