import { h } from 'vue'
import type { AviatorFunction } from '../../infrastructure/engine/types'
import { renderParameterList } from './useFunctionModeEditorController.usage.parameters'
import { getReturnTypeColor, getReturnTypeStyle } from './useFunctionModeEditorController.usage.styles'

export function renderFunctionUsageContent(
  func: AviatorFunction,
  options: { onCopyExample: () => void },
) {
  const returnTypeColor = getReturnTypeColor(func.returnType)
  const paramsContent = renderParameterList(func)

  return h('div', { style: { fontSize: '13px' } }, [
    h('div', { style: { marginBottom: '12px' } }, [
      h('div', { style: { fontWeight: 500, color: '#1d2129', marginBottom: '4px' } }, '函数说明：'),
      h('div', { style: { color: '#4e5969' } }, func.description),
    ]),
    h('div', { style: { marginBottom: '12px' } }, [
      h('div', { style: { fontWeight: 500, color: '#1d2129', marginBottom: '4px' } }, '参数列表：'),
      ...paramsContent,
    ]),
    h('div', { style: { marginBottom: '12px' } }, [
      h('div', { style: { fontWeight: 500, color: '#1d2129', marginBottom: '4px' } }, '返回类型：'),
      h('span', { style: getReturnTypeStyle(returnTypeColor) }, func.returnType),
    ]),
    h('div', [
      h('div', { style: { fontWeight: 500, color: '#1d2129', marginBottom: '4px' } }, '使用示例：'),
      h('div', {
        style: {
          display: 'flex',
          alignItems: 'center',
          gap: '8px',
          backgroundColor: '#f8f9fa',
          border: '1px solid #e5e6eb',
          borderRadius: '4px',
          padding: '8px 12px',
        },
      }, [
        h('code', {
          style: {
            flex: 1,
            fontFamily: 'Consolas, Monaco, monospace',
            fontSize: '13px',
            color: '#1d2129',
          },
        }, func.example),
        h('a', {
          style: {
            color: '#165dff',
            cursor: 'pointer',
            fontSize: '12px',
            textDecoration: 'none',
            flexShrink: 0,
          },
          onClick: options.onCopyExample,
        }, '复制'),
      ]),
    ]),
  ])
}
