import type { createValueInputComputedState } from './useValueInputController.state.computed'
import type { createValueInputQueries } from './useValueInputController.state.queries'
import type { createValueInputStateRefs } from './useValueInputController.state.refs'
import type { useFunctionRefValueController } from './function-ref-value-controller'

interface CreateValueInputControllerStateExposedOptions {
  refsState: ReturnType<typeof createValueInputStateRefs>
  computedState: ReturnType<typeof createValueInputComputedState>
  functionRefController: ReturnType<typeof useFunctionRefValueController>
  queries: ReturnType<typeof createValueInputQueries>
}

export function createValueInputControllerStateExposed(
  options: CreateValueInputControllerStateExposedOptions,
) {
  const { refsState, computedState, functionRefController, queries } = options

  return {
    userSelectedType: refsState.userSelectedType,
    savedStringValue: refsState.savedStringValue,
    savedFieldValue: refsState.savedFieldValue,
    savedFunctionValue: refsState.savedFunctionValue,
    urlError: refsState.urlError,
    userSelectedValueDataType: computedState.userSelectedValueDataType,
    dateValue: computedState.dateValue,
    multiValues: computedState.multiValues,
    functionRefController,
    getPlaceholder: queries.getPlaceholder,
    isCompoundOperator: queries.isCompoundOperator,
    getFieldTypeColor: queries.getFieldTypeColor,
    getValueInputType: queries.getValueInputType,
    getAvailableValueTypes: queries.getAvailableValueTypes,
    getValueDataType: queries.getValueDataType,
    getBaseFieldName: queries.getBaseFieldName,
    getValueArrayIndex: queries.getValueArrayIndex,
    getFieldTooltipForValue: queries.getFieldTooltipForValue,
    syncFunctionStateFromValue: queries.syncFunctionStateFromValue,
  }
}
