import { computed } from 'vue'
import type { ConditionNodeViewProps } from './types'

export function createConditionNodeMode(props: ConditionNodeViewProps) {
  return computed<'condition' | 'function'>(() => {
    if (props.node.field) {
      return 'condition'
    }
    if (props.node.functionName) {
      return 'function'
    }
    return 'condition'
  })
}
