import type { TreeExpressionBuilderBindingsController } from './types'

export function createTreeExpressionBuilderPreviewListeners(
  controller: TreeExpressionBuilderBindingsController,
) {
  return {
    clear: controller.clearExpression,
    validate: controller.validateExpressionManually,
    copy: controller.copyExpression,
    format: controller.formatExpression,
  } as const
}
