import { createFunctionRefParameterInputBodyListeners } from './input-body.listeners'
import { createFunctionRefParameterInputBodyState } from './input-body.state'
import type { UseFunctionRefParameterInputBindingsOptions } from './input-body.types'

export function setupFunctionRefParameterInputBodyBindings(
  options: UseFunctionRefParameterInputBindingsOptions,
) {
  const state = createFunctionRefParameterInputBodyState(options.props)
  const listeners = createFunctionRefParameterInputBodyListeners(options.emit)

  return {
    state,
    listeners,
  }
}
