import type { NodeValue } from '../../../../infrastructure/engine/types'

interface CreateParameterInputBaseListenersOptions {
  changeParameterType: (type: string) => void
  updateValue: (value: NodeValue) => void
  updateMultiValue: (values: string[]) => void
  changeValueDataType: (dataType: string) => void
}

export function createParameterInputBaseListeners(options: CreateParameterInputBaseListenersOptions) {
  const typeSelectorListeners = {
    'update:model-value': options.changeParameterType,
  }

  const valueModeListeners = {
    'update:value': options.updateValue,
    'update:multi-values': options.updateMultiValue,
    'update:value-data-type': options.changeValueDataType,
  }

  const fieldModeListeners = {
    'update:value': options.updateValue,
  }

  const lambdaModeListeners = {
    'update:value': options.updateValue,
  }

  return {
    typeSelectorListeners,
    valueModeListeners,
    fieldModeListeners,
    lambdaModeListeners,
  }
}
