import type { FunctionParameterUpdatePayload } from '../../editors/function-ref/types'
import type { ValueInputSwitchPanelEmits } from '../types'

export function createValueFunctionForwarders(emit: ValueInputSwitchPanelEmits) {
  const onUpdateFunction = (functionName: string) => emit('update:function', functionName)
  const onUpdateParameter = (payload: FunctionParameterUpdatePayload) => emit('update:parameter', payload)

  return {
    onUpdateFunction,
    onUpdateParameter,
  }
}
