import type { createParameterInputControllerDisplayValue } from './useParameterInputController.state.computed'
import type { createParameterInputControllerStateQueries } from './useParameterInputController.state.queries'
import type { createParameterInputControllerStateRefs } from './useParameterInputController.state.refs'

interface CreateParameterInputControllerStateExposedOptions {
  refs: ReturnType<typeof createParameterInputControllerStateRefs>
  displayValue: ReturnType<typeof createParameterInputControllerDisplayValue>
  queries: ReturnType<typeof createParameterInputControllerStateQueries>
}

export function createParameterInputControllerStateExposed(
  options: CreateParameterInputControllerStateExposedOptions,
) {
  const { refs, displayValue, queries } = options

  return {
    savedStringValue: refs.savedStringValue,
    userSelectedType: refs.userSelectedType,
    userHasSelectedDataType: refs.userHasSelectedDataType,
    userSelectedValueDataType: refs.userSelectedValueDataType,
    displayValue,
    isCurrentLambdaParameter: queries.isCurrentLambdaParameter,
    getParameterInputType: queries.getParameterInputType,
    getAvailableParameterTypes: queries.getAvailableParameterTypes,
    getMultiValue: queries.getMultiValue,
    getTypeColor: queries.getTypeColor,
    getFieldTooltipText: queries.getFieldTooltipText,
    getValueDataType: queries.getValueDataType,
  }
}
