import {
  appendChildNodeToGroup,
  removeNodeFromTree,
  resolveConditionValueDataType,
  setGroupExpandedRecursively,
  updateNodeInTree,
} from '../logic/treeExpressionBuilderLogic'
import { createGroupNode } from '../../infrastructure/engine/utils'
import type { TreeNode } from '../../infrastructure/engine/types'
import type { BuilderNodeType } from '../types/treeInteraction'
import type { TreeExpressionBuilderState } from './useTreeExpressionBuilderNodeActions.shared'

interface StructureActionsOptions {
  state: TreeExpressionBuilderState
  commitNodeMutation: (options?: { validate?: boolean }) => void
}

export function createTreeExpressionBuilderStructureActions(options: StructureActionsOptions) {
  const { state, commitNodeMutation } = options

  const addGroup = () => {
    state.rootNodes.value.push(createGroupNode(undefined, 0))
    commitNodeMutation({ validate: true })
  }

  const expandAll = () => {
    setGroupExpandedRecursively(state.rootNodes.value, true)
  }

  const collapseAll = () => {
    setGroupExpandedRecursively(state.rootNodes.value, false)
  }

  const updateNode = (nodeId: string, updates: Partial<TreeNode>) => {
    updateNodeInTree(state.rootNodes.value, nodeId, updates)
    const uiOnlyUpdate = 'expanded' in updates && Object.keys(updates).length === 1
    commitNodeMutation({ validate: !uiOnlyUpdate })
  }

  const addChildNode = (parentId: string, nodeType: BuilderNodeType) => {
    const result = appendChildNodeToGroup(state.rootNodes.value, parentId, nodeType, state.availableFields.value)
    if (!result.updated) return

    if (result.addedConditionNodeId) {
      state.service.setParameterDataType(
        result.addedConditionNodeId,
        'condition_value',
        result.addedConditionDataType || resolveConditionValueDataType(),
      )
    }

    commitNodeMutation({ validate: true })
  }

  const removeNode = (nodeId: string) => {
    state.rootNodes.value = removeNodeFromTree(state.rootNodes.value, nodeId)
    commitNodeMutation({ validate: true })
  }

  const handleParameterTypeUpdate = (_paramName: string, _type: string) => {
    state.regenerateExpression()
  }

  const handleParameterValueDataTypeUpdate = (nodeId: string, paramName: string, dataType: string) => {
    state.service.setParameterDataType(nodeId, paramName, dataType)
    state.regenerateExpression()
  }

  const getParameterDataType = (nodeId: string, paramName: string): string | undefined => {
    return state.parameterDataTypes.get(nodeId)?.get(paramName)
  }

  return {
    addGroup,
    expandAll,
    collapseAll,
    updateNode,
    addChildNode,
    removeNode,
    handleParameterTypeUpdate,
    handleParameterValueDataTypeUpdate,
    getParameterDataType,
  }
}
