import type { createTreeExpressionBuilderClipboardActions } from './useTreeExpressionBuilderExpressionActions.clipboard'
import type { createTreeExpressionBuilderLifecycleActions } from './useTreeExpressionBuilderExpressionActions.lifecycle'
import type { createTreeExpressionBuilderValidationActions } from './useTreeExpressionBuilderExpressionActions.validation'

interface CreateTreeExpressionBuilderExpressionActionsExposedOptions {
  lifecycleActions: ReturnType<typeof createTreeExpressionBuilderLifecycleActions>
  clipboardActions: ReturnType<typeof createTreeExpressionBuilderClipboardActions>
  validationActions: ReturnType<typeof createTreeExpressionBuilderValidationActions>
}

export function createTreeExpressionBuilderExpressionActionsExposed(
  options: CreateTreeExpressionBuilderExpressionActionsExposedOptions,
) {
  const { lifecycleActions, clipboardActions, validationActions } = options

  return {
    clearExpression: lifecycleActions.clearExpression,
    formatExpression: lifecycleActions.formatExpression,
    copyExpression: clipboardActions.copyExpression,
    validateExpressionManually: validationActions.validateExpressionManually,
  }
}
