import { watch } from 'vue'
import type { Ref } from 'vue'
import type { TreeExpressionBuilderProps } from './useTreeExpressionBuilder.types'

interface TreeExpressionBuilderWatcherOptions {
  props: TreeExpressionBuilderProps
  generatedExpression: Ref<string>
  loadExpression: (expression: string) => void
  syncServiceFields: () => void
  runValidation: () => void
}

export function setupTreeExpressionBuilderWatchers(options: TreeExpressionBuilderWatcherOptions) {
  const {
    props,
    generatedExpression,
    loadExpression,
    syncServiceFields,
    runValidation,
  } = options

  watch(
    () => props.modelValue,
    (newValue) => {
      if (newValue !== generatedExpression.value) {
        loadExpression(newValue)
      }
    },
    { immediate: true },
  )

  watch(
    () => [props.fieldOptions, props.dataPreview],
    () => {
      syncServiceFields()
      if (generatedExpression.value) {
        runValidation()
      }
    },
  )
}
