import type { TreeNode } from '../../types'

export function generateCopiedNodeId(nodeType: string): string {
  return `${nodeType}_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
}

export function deepCloneNode(node: TreeNode): TreeNode {
  return JSON.parse(JSON.stringify(node)) as TreeNode
}

export function cloneDataTypes(
  parameterDataTypes: Map<string, Map<string, string>>,
  sourceId: string,
  targetId: string,
) {
  const source = parameterDataTypes.get(sourceId)
  if (!source) return
  parameterDataTypes.set(targetId, new Map(source))
}
