import type { ValueInputSwitchPanelProps } from '../types'
import { createFieldRefEditorProps } from './panel-props.field'
import { createFunctionRefEditorProps } from './panel-props.function'
import { createValueEditorProps } from './panel-props.value'

export function createValueInputPanelBodyPanelProps(props: ValueInputSwitchPanelProps) {
  const valueEditorProps = createValueEditorProps(props)
  const fieldRefEditorProps = createFieldRefEditorProps(props)
  const functionRefEditorProps = createFunctionRefEditorProps(props)

  return {
    valueEditorProps,
    fieldRefEditorProps,
    functionRefEditorProps,
  }
}
