import { createFunctionModeEditorControllerActionsExposed } from './useFunctionModeEditorController.actions.exposed'
import { useFunctionModeEditorControllerFilterActions } from './useFunctionModeEditorController.filterActions'
import type { FunctionModeEditorControllerState } from './useFunctionModeEditorController.shared'
import { useFunctionModeEditorControllerUsageActions } from './useFunctionModeEditorController.usageActions'

export function useFunctionModeEditorControllerActions(
  state: FunctionModeEditorControllerState,
) {
  const filterActions = useFunctionModeEditorControllerFilterActions()
  const usageActions = useFunctionModeEditorControllerUsageActions(state)

  return createFunctionModeEditorControllerActionsExposed({
    filterActions,
    usageActions,
  })
}
