import type { NodeValue } from '../../../../../infrastructure/engine/types'
import type { ConditionValueEditorEmits } from './types'

export function createConditionValueEditorForwarders(emit: ConditionValueEditorEmits) {
  const onUpdateValue = (value: NodeValue) => {
    emit('update:value', value)
  }

  const onUpdateMultiValues = (values: string[]) => {
    emit('update:multi-values', values)
  }

  const onUpdateDateValue = (date: Date | undefined) => {
    emit('update:date-value', date)
  }

  const onBlurUrl = () => {
    emit('blur:url')
  }

  const onUpdateValueDataType = (dataType: string) => {
    emit('update:value-data-type', dataType)
  }

  return {
    onUpdateValue,
    onUpdateMultiValues,
    onUpdateDateValue,
    onBlurUrl,
    onUpdateValueDataType,
  }
}
