import type {
  ParameterInputControllerState,
  UseParameterInputControllerActionsOptions,
} from './useParameterInputController.actions.shared'

export function createChangeValueDataTypeAction(
  state: ParameterInputControllerState,
  options: UseParameterInputControllerActionsOptions,
) {
  const { props, emitUpdateValue, emitUpdateValueDataType } = options

  return (dataType: string) => {
    state.userHasSelectedDataType.value = true
    state.userSelectedValueDataType.value = dataType

    emitUpdateValueDataType(props.parameter.name, dataType)

    if (props.value !== undefined && props.value !== null && props.value !== '') {
      emitUpdateValue(props.value)
    }
  }
}
