import { computed } from 'vue'
import type { FieldRefEditorProps } from './types'

export function createFieldRefState(props: FieldRefEditorProps) {
  const baseFieldName = computed(() => {
    if (!props.value) return ''
    const match = props.value.match(/^(.+)\[(\d+)\]$/)
    return match ? match[1] : props.value
  })

  const currentFieldValue = computed(() => {
    return props.showArrayIndex ? baseFieldName.value : (props.value || '')
  })

  const isArrayField = computed(() => {
    const field = props.availableFields.find((item) => item.value === baseFieldName.value)
    return field?.type === 'array'
  })

  return {
    baseFieldName,
    currentFieldValue,
    isArrayField,
  }
}
