import type { setupFunctionRefEditorBindings } from './setup'

interface CreateFunctionRefEditorExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionRefEditorBindings>
}

export function createFunctionRefEditorExposedBindings(
  options: CreateFunctionRefEditorExposedBindingsOptions,
) {
  const { listeners, viewModel } = options.setupResult

  return {
    hasSelectedFunction: viewModel.hasSelectedFunction,
    showParameters: viewModel.showParameters,
    selectorProps: viewModel.selectorProps,
    parameterProps: viewModel.parameterProps,
    previewProps: viewModel.previewProps,
    selectorListeners: listeners.selectorListeners,
    parameterListeners: listeners.parameterListeners,
  }
}
