import type { useTreeExpressionBuilderExpressionActions } from './useTreeExpressionBuilderExpressionActions'
import type { useTreeExpressionBuilderNodeActions } from './useTreeExpressionBuilderNodeActions'

interface CreateTreeExpressionBuilderActionsExposedOptions {
  nodeActions: ReturnType<typeof useTreeExpressionBuilderNodeActions>
  expressionActions: ReturnType<typeof useTreeExpressionBuilderExpressionActions>
}

export function createTreeExpressionBuilderActionsExposed(
  options: CreateTreeExpressionBuilderActionsExposedOptions,
) {
  const { nodeActions, expressionActions } = options

  return {
    addGroup: nodeActions.addGroup,
    expandAll: nodeActions.expandAll,
    collapseAll: nodeActions.collapseAll,
    updateNode: nodeActions.updateNode,
    addChildNode: nodeActions.addChildNode,
    removeNode: nodeActions.removeNode,
    moveNodeUpAction: nodeActions.moveNodeUpAction,
    moveNodeDownAction: nodeActions.moveNodeDownAction,
    copyNodeAction: nodeActions.copyNodeAction,
    handleParameterTypeUpdate: nodeActions.handleParameterTypeUpdate,
    handleParameterValueDataTypeUpdate: nodeActions.handleParameterValueDataTypeUpdate,
    handleDragNode: nodeActions.handleDragNode,
    getParameterDataType: nodeActions.getParameterDataType,
    clearExpression: expressionActions.clearExpression,
    validateExpressionManually: expressionActions.validateExpressionManually,
    copyExpression: expressionActions.copyExpression,
    formatExpression: expressionActions.formatExpression,
  }
}
