import { createParameterInputModeProps } from './view-model-mode-props'
import { createParameterInputModeFlags } from './view-model-modes'
import { createParameterInputViewModelExposed } from './view-model.exposed'
import { createParameterInputSelectorViewModel } from './view-model-selector'
import type { CreateParameterInputViewModelOptions } from './view-model.types'

export function createParameterInputViewModel(options: CreateParameterInputViewModelOptions) {
  const { props, controller, state } = options

  const selectorViewModel = createParameterInputSelectorViewModel({
    props,
    state,
  })
  const modeFlags = createParameterInputModeFlags({ state })
  const modeProps = createParameterInputModeProps({
    props,
    controller,
    state,
  })

  return createParameterInputViewModelExposed({
    selectorViewModel,
    modeFlags,
    modeProps,
  })
}
