import { createFieldModeControlsExposedBindings } from './field-mode-controls-bindings/exposed'
import { setupFieldModeControlsBindings } from './field-mode-controls-bindings/setup'
import type {
  UseFieldModeControlsBindingsOptions,
} from './field-mode-controls-bindings/types'

export type {
  FieldModeControlsEmits,
  FieldModeControlsProps,
  UseFieldModeControlsBindingsOptions,
} from './field-mode-controls-bindings/types'

export function useFieldModeControlsBindings(options: UseFieldModeControlsBindingsOptions) {
  const setupResult = setupFieldModeControlsBindings(options)
  return createFieldModeControlsExposedBindings({ setupResult })
}
