import type { createTreeNodeViewForwarders } from '../useTreeNodeViewBindings.forwarders'
import type { createTreeNodeViewHandlers } from '../useTreeNodeViewBindings.handlers'
import type { createTreeNodeControllerBindings } from './controller'
import type { createTreeNodeClasses } from './nodeClasses'

interface CreateTreeNodeViewExposedBindingsOptions {
  controller: ReturnType<typeof createTreeNodeControllerBindings>
  handlers: ReturnType<typeof createTreeNodeViewHandlers>
  forwarders: ReturnType<typeof createTreeNodeViewForwarders>
  nodeClasses: ReturnType<typeof createTreeNodeClasses>
}

export function createTreeNodeViewExposedBindings(options: CreateTreeNodeViewExposedBindingsOptions) {
  const { controller, handlers, forwarders, nodeClasses } = options

  return {
    hasError: controller.hasError,
    indentSize: controller.indentSize,
    nodeClasses,
    toggleExpanded: controller.toggleExpanded,
    updateBaseField: controller.updateBaseField,
    updateArrayIndex: controller.updateArrayIndex,
    switchConditionMode: controller.switchConditionMode,
    updateComparison: controller.updateComparison,
    updateValue: controller.updateValue,
    updateExtraComparison: controller.updateExtraComparison,
    updateOperator: controller.updateOperator,
    updateFunction: controller.updateFunction,
    updateConditionNegation: controller.updateConditionNegation,
    updateGroupNegation: controller.updateGroupNegation,
    copyNode: controller.copyNode,
    getAvailableOperators: controller.getAvailableOperators,
    handleDragStart: controller.handleDragStart,
    handleDragEnd: controller.handleDragEnd,
    handleDragOver: controller.handleDragOver,
    handleDragLeave: controller.handleDragLeave,
    handleDrop: controller.handleDrop,
    onConditionValueDataType: handlers.onConditionValueDataType,
    onFunctionValueDataType: handlers.onFunctionValueDataType,
    onParameterUpdate: handlers.onParameterUpdate,
    onParameterTypeUpdate: handlers.onParameterTypeUpdate,
    onParameterValueTypeUpdate: handlers.onParameterValueTypeUpdate,
    forwardUpdateNode: forwarders.forwardUpdateNode,
    forwardAddChild: forwarders.forwardAddChild,
    forwardRemoveNode: forwarders.forwardRemoveNode,
    forwardMoveUp: forwarders.forwardMoveUp,
    forwardMoveDown: forwarders.forwardMoveDown,
    forwardCopyNode: forwarders.forwardCopyNode,
    forwardUpdateParameterType: forwarders.forwardUpdateParameterType,
    forwardUpdateParameterValueDataType: forwarders.forwardUpdateParameterValueDataType,
    forwardDragNode: forwarders.forwardDragNode,
  }
}
