import type { useTreeNodeFieldMutation } from './useTreeNodeFieldMutation'
import type { useTreeNodeMutationCondition } from './useTreeNodeMutation.condition'
import type { useTreeNodeMutationUi } from './useTreeNodeMutation.ui'
import type { useTreeNodeParameterMutation } from './useTreeNodeParameterMutation'

interface CreateTreeNodeMutationExposedOptions {
  uiMutation: ReturnType<typeof useTreeNodeMutationUi>
  fieldMutation: ReturnType<typeof useTreeNodeFieldMutation>
  conditionMutation: ReturnType<typeof useTreeNodeMutationCondition>
  parameterMutation: ReturnType<typeof useTreeNodeParameterMutation>
}

export function createTreeNodeMutationExposed(options: CreateTreeNodeMutationExposedOptions) {
  const { uiMutation, fieldMutation, conditionMutation, parameterMutation } = options

  return {
    hasError: uiMutation.hasError,
    indentSize: uiMutation.indentSize,
    toggleExpanded: uiMutation.toggleExpanded,
    updateOperator: uiMutation.updateOperator,
    updateConditionNegation: uiMutation.updateConditionNegation,
    updateGroupNegation: uiMutation.updateGroupNegation,
    copyNode: uiMutation.copyNode,
    updateBaseField: fieldMutation.updateBaseField,
    updateArrayIndex: fieldMutation.updateArrayIndex,
    getAvailableOperators: fieldMutation.getAvailableOperators,
    switchConditionMode: conditionMutation.switchConditionMode,
    updateComparison: conditionMutation.updateComparison,
    updateValue: conditionMutation.updateValue,
    updateExtraComparison: conditionMutation.updateExtraComparison,
    updateFunction: conditionMutation.updateFunction,
    updateParameter: parameterMutation.updateParameter,
    updateParameterType: parameterMutation.updateParameterType,
    updateParameterValueDataType: parameterMutation.updateParameterValueDataType,
    updateConditionValueDataType: parameterMutation.updateConditionValueDataType,
    updateFunctionValueDataType: parameterMutation.updateFunctionValueDataType,
  }
}
