import { setDragTargetOpacity } from './style'

interface DragStartEndOptions {
  nodeId: string
  clearAllDragStates: () => void
}

export function createTreeNodeDragStartEndHandlers(options: DragStartEndOptions) {
  const { nodeId, clearAllDragStates } = options

  const handleDragStart = (event: DragEvent) => {
    if (!event.dataTransfer) {
      return
    }

    event.dataTransfer.setData('text/plain', nodeId)
    event.dataTransfer.effectAllowed = 'move'
    setDragTargetOpacity(event, '0.5')
    clearAllDragStates()
  }

  const handleDragEnd = (event: DragEvent) => {
    setDragTargetOpacity(event, '1')
    clearAllDragStates()
  }

  return {
    handleDragStart,
    handleDragEnd,
  }
}
