import type { TreeNode } from '../../types'
import type { OperationResult } from './types'
import { findAndCloneNode, insertCopiedNode } from './copy-tree'

export function copyNode(
  nodes: TreeNode[],
  nodeId: string,
  parameterDataTypes: Map<string, Map<string, string>>,
): OperationResult {
  const copiedNode = findAndCloneNode({
    nodes,
    nodeId,
    parameterDataTypes,
  })
  if (!copiedNode) {
    return { success: false, reason: 'node_not_found' }
  }

  if (!insertCopiedNode({
    nodes,
    targetId: nodeId,
    copiedNode,
  })) {
    return { success: false, reason: 'node_not_found' }
  }

  return { success: true }
}
