import { computed } from 'vue'
import type { ConditionValueEditorProps } from './types'

export function createConditionValueEditorState(props: ConditionValueEditorProps) {
  const isNullComparison = computed(() => {
    return props.comparison === '== nil' || props.comparison === '!= nil'
  })

  const isMultiValue = computed(() => {
    return props.comparison === 'in'
      || props.comparison === '!in'
      || props.comparison === 'belong'
      || props.comparison === 'isIpInNetmaskList'
  })

  const multiValuePlaceholder = computed(() => {
    if (props.comparison === 'belong') {
      return '输入数组元素，回车分隔'
    }
    if (props.comparison === 'isIpInNetmaskList') {
      return '输入网段，如 10.128.16.0/20'
    }
    return '输入多个值，回车分隔'
  })

  const multiValueTooltip = computed(() => {
    if (props.comparison === 'belong') {
      return '输入数组元素，回车分隔。将判断字段数组是否包含这些元素中的任意一个'
    }

    if (props.comparison === 'isIpInNetmaskList') {
      return '输入多个网段（CIDR格式），回车分隔。如：10.128.16.0/20、192.168.1.0/24'
    }

    return '多个值用回车分隔，支持字符串和数字'
  })

  const showValueDataTypeSwitch = computed(() => {
    return props.showDataTypeSwitch && props.comparison !== 'isIpInNetmaskList'
  })

  return {
    isNullComparison,
    isMultiValue,
    multiValuePlaceholder,
    multiValueTooltip,
    showValueDataTypeSwitch,
  }
}
