import { formatExpressionText } from '../logic/treeExpressionBuilderLogic'
import type { TreeExpressionBuilderNotifier } from './treeExpressionBuilderNotifier'
import type { TreeExpressionBuilderState } from './useTreeExpressionBuilderExpressionActions.shared'

interface LifecycleActions {
  clearExpression: () => void
  formatExpression: () => void
}

export function createTreeExpressionBuilderLifecycleActions(
  state: TreeExpressionBuilderState,
  notifier: TreeExpressionBuilderNotifier,
): LifecycleActions {
  const clearExpression = () => {
    state.rootNodes.value = []
    state.service.clearParameterDataTypes()
    state.parseError.value = null
    state.validationErrors.value = []
    state.validationResult.value = null
    state.emitExpression('')
    notifier.success('表达式已清空')
  }

  const formatExpression = () => {
    if (!state.generatedExpression.value) return

    const formatted = formatExpressionText(state.generatedExpression.value)
    state.emitExpression(formatted)
  }

  return {
    clearExpression,
    formatExpression,
  }
}
