import type { FunctionRefParameterInputEmits, FunctionRefParameterInputPayload } from './types'

export function createFunctionRefParameterInputForwarders(emit: FunctionRefParameterInputEmits) {
  const onUpdateValue = (payload: FunctionRefParameterInputPayload) => {
    emit('update:parameter', payload)
  }

  return {
    onUpdateValue,
  }
}
