import type { createValueFieldForwarders } from './forwarders/field-forwarders'
import type { createValueFunctionForwarders } from './forwarders/function-forwarders'
import type { createValueTypeForwarders } from './forwarders/type-forwarders'
import type { createValueEditForwarders } from './forwarders/value-forwarders'

interface CreateValueInputForwardersExposedOptions {
  typeForwarders: ReturnType<typeof createValueTypeForwarders>
  valueForwarders: ReturnType<typeof createValueEditForwarders>
  fieldForwarders: ReturnType<typeof createValueFieldForwarders>
  functionForwarders: ReturnType<typeof createValueFunctionForwarders>
}

export function createValueInputForwardersExposed(
  options: CreateValueInputForwardersExposedOptions,
) {
  const {
    typeForwarders,
    valueForwarders,
    fieldForwarders,
    functionForwarders,
  } = options

  return {
    onUpdateType: typeForwarders.onUpdateType,
    onUpdateValue: valueForwarders.onUpdateValue,
    onUpdateMultiValues: valueForwarders.onUpdateMultiValues,
    onUpdateDateValue: valueForwarders.onUpdateDateValue,
    onBlurUrl: valueForwarders.onBlurUrl,
    onUpdateValueDataType: valueForwarders.onUpdateValueDataType,
    onUpdateField: fieldForwarders.onUpdateField,
    onUpdateArrayIndex: fieldForwarders.onUpdateArrayIndex,
    onUpdateFunction: functionForwarders.onUpdateFunction,
    onUpdateParameter: functionForwarders.onUpdateParameter,
  }
}
