import type { UseFunctionCatalogSelectBindingsOptions } from './types'

export function setupFunctionCatalogSelectBindings(options: UseFunctionCatalogSelectBindingsOptions) {
  const { emit } = options

  const selectListeners = {
    'update:model-value': (value: string) => emit('update:modelValue', value),
  } as const

  return {
    selectListeners,
  }
}
