import { ref } from 'vue'
import type {
  CreateLegacyModalBindingsOptions,
  LegacyModalFieldOption,
} from './types'

export function setupAviatorExpressionBuilderLegacyModalBindings(
  options: CreateLegacyModalBindingsOptions,
) {
  const { emit, notifier } = options

  const visible = ref(false)
  const currentExpression = ref('')
  const dataPreview = ref('')
  const fieldOptions = ref<LegacyModalFieldOption[]>([])

  const reset = () => {
    currentExpression.value = ''
  }

  const handleOk = (expression?: string) => {
    const nextExpression = expression ?? currentExpression.value
    if (!nextExpression) {
      notifier.warning('请构建表达式')
      return
    }

    currentExpression.value = nextExpression
    emit('save', nextExpression)
    visible.value = false
    reset()
  }

  const handleCancel = () => {
    visible.value = false
    reset()
  }

  const open = (
    initialExpression?: string,
    customFieldOptions?: LegacyModalFieldOption[],
    previewData?: string,
  ) => {
    currentExpression.value = initialExpression || ''
    dataPreview.value = previewData || ''

    if (customFieldOptions && customFieldOptions.length > 0) {
      fieldOptions.value = customFieldOptions
    } else {
      fieldOptions.value = []
    }

    visible.value = true
  }

  const updateFieldOptions = (options: LegacyModalFieldOption[]) => {
    fieldOptions.value = options
  }

  return {
    visible,
    currentExpression,
    dataPreview,
    fieldOptions,
    handleOk,
    handleCancel,
    open,
    updateFieldOptions,
  }
}
