import type { TreeNode } from '../../../../infrastructure/engine/types'
import type { BuilderNodeType, TreeDragPosition } from '../../../types/treeInteraction'
import type { UseTreeNodeChildrenBindingsOptions } from './types'

export function createTreeNodeChildrenForwarders(options: UseTreeNodeChildrenBindingsOptions) {
  const { emit } = options

  const onUpdateNode = (nodeId: string, updates: Partial<TreeNode>) => {
    emit('update-node', nodeId, updates)
  }

  const onAddChild = (parentId: string, nodeType: BuilderNodeType) => {
    emit('add-child', parentId, nodeType)
  }

  const onRemoveNode = (nodeId: string) => {
    emit('remove-node', nodeId)
  }

  const onMoveUp = (nodeId: string) => {
    emit('move-up', nodeId)
  }

  const onMoveDown = (nodeId: string) => {
    emit('move-down', nodeId)
  }

  const onCopyNode = (nodeId: string) => {
    emit('copy-node', nodeId)
  }

  const onUpdateParameterType = (paramName: string, type: string) => {
    emit('update-parameter-type', paramName, type)
  }

  const onUpdateParameterValueDataType = (nodeId: string, paramName: string, dataType: string) => {
    emit('update-parameter-value-data-type', nodeId, paramName, dataType)
  }

  const onDragNode = (sourceNodeId: string, targetNodeId: string, position: TreeDragPosition) => {
    emit('drag-node', sourceNodeId, targetNodeId, position)
  }

  return {
    onUpdateNode,
    onAddChild,
    onRemoveNode,
    onMoveUp,
    onMoveDown,
    onCopyNode,
    onUpdateParameterType,
    onUpdateParameterValueDataType,
    onDragNode,
  }
}
