import type { FieldOption, FunctionParameter } from '../../../infrastructure/engine/types'

export function isParameterInputType(value: string): value is 'value' | 'field' | 'condition' | 'lambda' {
  return value === 'value' || value === 'field' || value === 'condition' || value === 'lambda'
}

export function resolveRawType(parameter: FunctionParameter): string | undefined {
  const raw = parameter as unknown as Record<string, unknown>
  return typeof raw.type === 'string' ? raw.type : undefined
}

export function isTreeNodeLike(value: unknown): boolean {
  if (!value || typeof value !== 'object') {
    return false
  }
  const node = value as Record<string, unknown>
  return typeof node.id === 'string' && (node.type === 'condition' || node.type === 'group')
}

export function isLambdaValue(value: unknown): boolean {
  return typeof value === 'string' && value.includes('lambda(')
}

export function isFieldValue(value: unknown, availableFields: FieldOption[]): boolean {
  return typeof value === 'string' && !!value && availableFields.some((field) => field.value === value)
}
