import type { NodeValue } from '../../../../infrastructure/engine/types'
import type { FunctionParameterUpdatePayload } from '../editors/function-ref/types'

export interface ValueInputPanelBodyForwarders {
  onUpdateValue: (value: NodeValue) => void
  onUpdateMultiValues: (values: string[]) => void
  onUpdateDateValue: (date: Date | undefined) => void
  onBlurUrl: () => void
  onUpdateValueDataType: (dataType: string) => void
  onUpdateField: (value: string) => void
  onUpdateArrayIndex: (index: number | undefined) => void
  onUpdateFunction: (functionName: string) => void
  onUpdateParameter: (payload: FunctionParameterUpdatePayload) => void
}

export function createValueInputPanelBodyEventListeners(forwarders: ValueInputPanelBodyForwarders) {
  return {
    'update:value': forwarders.onUpdateValue,
    'update:multi-values': forwarders.onUpdateMultiValues,
    'update:date-value': forwarders.onUpdateDateValue,
    'blur:url': forwarders.onBlurUrl,
    'update:value-data-type': forwarders.onUpdateValueDataType,
    'update:field': forwarders.onUpdateField,
    'update:array-index': forwarders.onUpdateArrayIndex,
    'update:function': forwarders.onUpdateFunction,
    'update:parameter': forwarders.onUpdateParameter,
  } as const
}

export type ValueInputPanelBodyEventListeners = ReturnType<typeof createValueInputPanelBodyEventListeners>

export function createValueEditorListenersFromPanelBody(
  listeners: ValueInputPanelBodyEventListeners,
) {
  return {
    'update:value': listeners['update:value'],
    'update:multi-values': listeners['update:multi-values'],
    'update:date-value': listeners['update:date-value'],
    'blur:url': listeners['blur:url'],
    'update:value-data-type': listeners['update:value-data-type'],
  } as const
}

export function createFieldRefListenersFromPanelBody(
  listeners: ValueInputPanelBodyEventListeners,
) {
  return {
    'update:field': listeners['update:field'],
    'update:array-index': listeners['update:array-index'],
  } as const
}

export function createFunctionRefListenersFromPanelBody(
  listeners: ValueInputPanelBodyEventListeners,
) {
  return {
    'update:function': listeners['update:function'],
    'update:parameter': listeners['update:parameter'],
  } as const
}
