import { computed } from 'vue'
import { AVIATOR_FUNCTIONS } from '../../infrastructure/engine/constants'
import type { ComparisonOperator, FunctionParameter } from '../../infrastructure/engine/types'
import type {
  FunctionModeEditorProps,
} from './useFunctionModeEditorController.types'
import { buildFunctionCategories } from './useFunctionModeEditorController.state.categories'
import { RETURN_TYPE_OPERATORS } from './useFunctionModeEditorController.state.constants'
import { isReturnTypeCompatible, normalizeType } from './useFunctionModeEditorController.state.helpers'
import {
  getParameterActualValue as resolveParameterActualValue,
  getParameterWithValue as resolveParameterWithValue,
} from './useFunctionModeEditorController.state.parameters'

export interface UseFunctionModeEditorControllerStateOptions {
  props: FunctionModeEditorProps
}

export function useFunctionModeEditorControllerState(options: UseFunctionModeEditorControllerStateOptions) {
  const { props } = options

  const selectedFunction = computed(() => {
    if (!props.node.functionName) return null
    return AVIATOR_FUNCTIONS.find((func) => func.name === props.node.functionName) || null
  })

  const functionCategories = computed(() => {
    return buildFunctionCategories()
  })

  const shouldShowComparison = computed(() => {
    if (!selectedFunction.value) return false

    const expectedType = normalizeType(props.expectedReturnType)
    const actualReturnType = normalizeType(selectedFunction.value.returnType)
    if (isReturnTypeCompatible(actualReturnType, expectedType)) {
      return false
    }

    return selectedFunction.value.returnType !== 'boolean' || props.node.comparison
  })

  const returnTypeOperators = computed((): ComparisonOperator[] => {
    if (!selectedFunction.value) return []
    const returnType = selectedFunction.value.returnType
    return RETURN_TYPE_OPERATORS[returnType] || RETURN_TYPE_OPERATORS.string || []
  })

  const getParameterActualValue = (paramName: string) => {
    return resolveParameterActualValue(props.node, paramName)
  }

  const getParameterWithValue = (paramDef: FunctionParameter) => {
    return resolveParameterWithValue(props.node, paramDef)
  }

  return {
    selectedFunction,
    functionCategories,
    shouldShowComparison,
    returnTypeOperators,
    getParameterActualValue,
    getParameterWithValue,
  }
}
