import { createTreeExpressionBuilderStateExposed } from './useTreeExpressionBuilderState.exposed'
import {
  type SetupTreeExpressionBuilderStateOptions,
  setupTreeExpressionBuilderState,
} from './useTreeExpressionBuilderState.setup'

export type UseTreeExpressionBuilderStateOptions = SetupTreeExpressionBuilderStateOptions

export function useTreeExpressionBuilderState(options: UseTreeExpressionBuilderStateOptions) {
  const setupResult = setupTreeExpressionBuilderState(options)
  return createTreeExpressionBuilderStateExposed({ setupResult })
}
