import { createConditionValueInputSwitchListeners } from './listeners'
import { createConditionValueInputSwitchPanelProps } from './panelProps'
import type { ConditionValueInputSwitchEmits, ConditionValueInputSwitchProps } from './types'

interface SetupConditionValueInputSwitchBindingsOptions {
  props: ConditionValueInputSwitchProps
  emit: ConditionValueInputSwitchEmits
}

export function setupConditionValueInputSwitchBindings(
  options: SetupConditionValueInputSwitchBindingsOptions,
) {
  const { props, emit } = options

  const panelProps = createConditionValueInputSwitchPanelProps(props)
  const listeners = createConditionValueInputSwitchListeners(emit)

  return {
    panelProps,
    listeners,
  }
}
