import { ref, watch } from 'vue'
import type { UseAviatorExpressionBuilderModalBindingsOptions } from './types'

export function setupAviatorExpressionBuilderModalBindings(
  options: UseAviatorExpressionBuilderModalBindingsOptions,
) {
  const { props, emit } = options
  const localExpression = ref(props.modelValue || '')

  watch(
    () => props.visible,
    (visible) => {
      if (visible) {
        localExpression.value = props.modelValue || ''
      }
    },
  )

  watch(
    () => props.modelValue,
    (value) => {
      if (value !== localExpression.value) {
        localExpression.value = value || ''
      }
    },
  )

  watch(localExpression, (value) => {
    emit('update:modelValue', value)
  })

  const handleSave = () => {
    emit('save', localExpression.value)
    emit('update:visible', false)
  }

  const handleCancel = () => {
    localExpression.value = props.modelValue || ''
    emit('cancel')
    emit('update:visible', false)
  }

  return {
    localExpression,
    handleSave,
    handleCancel,
  }
}
