import type { TreeNodeEditorPanelBindings } from './types'

interface CreateTreeNodeEditorPanelListenersOptions {
  bindings: TreeNodeEditorPanelBindings
}

export function createTreeNodeEditorPanelListeners(options: CreateTreeNodeEditorPanelListenersOptions) {
  const { bindings } = options

  const conditionListeners = {
    'update:negation': bindings.onConditionNegation,
    'switch:mode': bindings.onSwitchMode,
    'update:field': bindings.onUpdateField,
    'update:array-index': bindings.onUpdateArrayIndex,
    'update:comparison': bindings.onUpdateComparison,
    'update:value': bindings.onUpdateValue,
    'update:extra-comparison': bindings.onUpdateExtraComparison,
    'update:value-data-type': bindings.onUpdateValueDataType,
    'update:function': bindings.onUpdateFunction,
    'update:parameter': bindings.onUpdateParameter,
    'update:parameter-type': bindings.onUpdateParameterType,
    'update:parameter-value-type': bindings.onUpdateParameterValueType,
    'update:function-value-data-type': bindings.onUpdateFunctionValueDataType,
  }

  const groupListeners = {
    'update:operator': bindings.onUpdateGroupOperator,
    'update:negation': bindings.onUpdateGroupNegation,
  }

  return {
    conditionListeners,
    groupListeners,
  }
}
