import { createFunctionParameterItemExposedBindings } from './item-bindings/exposed'
import { setupFunctionParameterItemBindings } from './item-bindings/setup'
import type {
  UseFunctionParameterItemBindingsOptions,
} from './item-bindings/types'

export type {
  FunctionParameterItemEmits,
  FunctionParameterItemProps,
  UseFunctionParameterItemBindingsOptions,
} from './item-bindings/types'

export function useFunctionParameterItemBindings(options: UseFunctionParameterItemBindingsOptions) {
  const setupResult = setupFunctionParameterItemBindings(options)
  return createFunctionParameterItemExposedBindings({ setupResult })
}
