import { computed } from 'vue'
import type { ParameterValueEditorProps } from './types'

interface ParameterValueEditorPanelState {
  resolvedDisplayValue: { value: ParameterValueEditorProps['value'] }
  isFormatParameter: { value: boolean }
  isTimezoneParameter: { value: boolean }
  isMultiValue: { value: boolean }
  multiValuePlaceholder: { value: string }
}

export function createParameterValueEditorPanelProps(
  props: ParameterValueEditorProps,
  state: ParameterValueEditorPanelState,
) {
  const valueInputSwitchProps = computed(() => ({
    resolvedDisplayValue: state.resolvedDisplayValue.value,
    valueDataType: props.valueDataType,
    isFormatParameter: state.isFormatParameter.value,
    isTimezoneParameter: state.isTimezoneParameter.value,
    isMultiValue: state.isMultiValue.value,
    multiValues: props.multiValues,
    multiValuePlaceholder: state.multiValuePlaceholder.value,
  }))

  const dataTypeSwitchProps = computed(() => ({
    modelValue: props.valueDataType,
  }))

  return {
    valueInputSwitchProps,
    dataTypeSwitchProps,
  }
}
