import type { setupFieldModeEditorBindings } from './setup'

interface CreateFieldModeEditorExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFieldModeEditorBindings>
}

export function createFieldModeEditorExposedBindings(
  options: CreateFieldModeEditorExposedBindingsOptions,
) {
  const { controller, currentDataType, listeners } = options.setupResult

  return {
    baseFieldName: controller.baseFieldName,
    arrayIndex: controller.arrayIndex,
    isArrayField: controller.isArrayField,
    fieldType: controller.fieldType,
    needsValue: controller.needsValue,
    getFieldTooltip: controller.getFieldTooltip,
    getTypeColor: controller.getTypeColor,
    currentDataType,
    controlsListeners: listeners.controlsListeners,
    valueInputListeners: listeners.valueInputListeners,
  }
}
