import type { TreeNode } from '../../infrastructure/engine/types'
import {
  type UseParameterInputControllerActionsOptions,
  resolveNestedTreeNode,
} from './useParameterInputController.actions.shared'

interface ParameterInputNestedActions {
  updateNestedNode: (nodeId: string, updates: Partial<TreeNode>) => void
  updateNestedParameterType: (paramName: string, type: string) => void
}

export function createParameterInputNestedActions(
  options: UseParameterInputControllerActionsOptions,
): ParameterInputNestedActions {
  const { props, emitUpdateValue } = options

  const updateNestedNode = (nodeId: string, updates: Partial<TreeNode>) => {
    const currentNestedNode = resolveNestedTreeNode(props.parameter, props.value)
    if (!currentNestedNode || currentNestedNode.id !== nodeId) return

    emitUpdateValue({
      ...currentNestedNode,
      ...updates,
    })
  }

  const updateNestedParameterType = (paramName: string, type: string) => {
    const currentNestedNode = resolveNestedTreeNode(props.parameter, props.value)
    if (!currentNestedNode || !currentNestedNode.parameters) return

    const parameters = currentNestedNode.parameters.map((param) => ({ ...param }))
    const paramIndex = parameters.findIndex((param) => param.name === paramName)

    if (paramIndex < 0) return

    parameters[paramIndex] = {
      ...parameters[paramIndex],
      type: type as 'field' | 'value' | 'expression',
    }

    emitUpdateValue({
      ...currentNestedNode,
      parameters,
    })
  }

  return {
    updateNestedNode,
    updateNestedParameterType,
  }
}
