import {
  type TreeNodeEventEmits,
  createTreeNodeEventForwarders,
  createTreeNodeListeners,
} from '../../shared/tree-node-events/index'

export type ConditionTreeEventEmits = TreeNodeEventEmits

export const createConditionTreeEventForwarders = createTreeNodeEventForwarders

export function createConditionTreeListeners(
  options: Parameters<typeof createTreeNodeListeners>[0],
) {
  const { treeNodeListeners } = createTreeNodeListeners(options)
  return {
    conditionTreeListeners: treeNodeListeners,
  }
}
