import type { setupFunctionModeEditorBindings } from './setup'

interface CreateFunctionModeEditorExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionModeEditorBindings>
}

export function createFunctionModeEditorExposedBindings(
  options: CreateFunctionModeEditorExposedBindingsOptions,
) {
  const {
    controller,
    listeners,
    shouldRenderComparison,
    comparisonSelectedFunction,
  } = options.setupResult

  return {
    selectedFunction: controller.selectedFunction,
    comparisonSelectedFunction,
    functionCategories: controller.functionCategories,
    filterFunctionOption: controller.filterFunctionOption,
    returnTypeOperators: controller.returnTypeOperators,
    getParameterActualValue: controller.getParameterActualValue,
    getParameterWithValue: controller.getParameterWithValue,
    shouldRenderComparison,
    functionSelectListeners: listeners.functionSelectListeners,
    parameterListListeners: listeners.parameterListListeners,
    comparisonPanelListeners: listeners.comparisonPanelListeners,
  }
}
