import { computed } from 'vue'
import type { TreeNode } from '../../../../infrastructure/engine/types'
import { createConditionNode } from '../../../../infrastructure/engine/utils'
import type { ParameterInputType } from '../../../logic/parameter-input'
import type { ParameterInputProps } from '../../../composables/useParameterInputController'

const fallbackConditionNode = createConditionNode(undefined, 1)

export function createParameterInputState(
  props: ParameterInputProps,
  getParameterInputType: () => ParameterInputType,
  getAvailableParameterTypes: () => Array<{ value: ParameterInputType, label: string }>,
) {
  const conditionNode = computed<TreeNode>(() => {
    const source = props.parameter.nestedNode ?? props.value
    if (source && typeof source === 'object' && 'id' in source && 'type' in source) {
      return source as TreeNode
    }
    return fallbackConditionNode
  })

  const currentParameterInputType = computed(() => getParameterInputType())
  const parameterTypeOptions = computed(() => getAvailableParameterTypes())

  return {
    conditionNode,
    currentParameterInputType,
    parameterTypeOptions,
  }
}
