import type { FieldOption } from '../../../infrastructure/engine/types'
import { FIELD_COLOR_MAP } from './constants'

export function getFieldTypeColor(type?: string): string {
  if (!type) return 'default'
  return FIELD_COLOR_MAP[type] || 'default'
}

export function getValuePlaceholder(fieldType?: string): string {
  switch (fieldType) {
    case 'string':
      return '输入文本'
    case 'email':
      return '输入邮箱地址'
    case 'url':
      return '输入URL地址'
    case 'uuid':
      return '输入UUID'
    default:
      return '输入值'
  }
}

export function getBaseFieldNameFromReference(value: unknown): string {
  if (typeof value !== 'string' || !value) return ''
  const match = value.match(/^([a-z_][\w.]*)(\[[^\]]+\])?$/i)
  return match ? match[1] : value
}

export function getArrayIndexFromReference(value: unknown): number | undefined {
  if (typeof value !== 'string' || !value) return undefined
  const match = value.match(/\[(\d+)\]$/)
  return match ? Number.parseInt(match[1], 10) : undefined
}

export function isArrayFieldReference(value: unknown, availableFields?: readonly FieldOption[]): boolean {
  const baseField = getBaseFieldNameFromReference(value)
  if (!baseField || !availableFields?.length) return false
  const matched = availableFields.find((field) => field.value === baseField)
  return matched?.type === 'array'
}

export function getFieldTooltip(field: FieldOption): string {
  if (field.type === 'array') {
    return `${field.label} (数组) - 可输入索引访问元素，例如: ${field.value}[0]`
  }

  return `字段: ${field.label} (${field.type})`
}
