import { createTreeExpressionBuilderClipboardActions } from './useTreeExpressionBuilderExpressionActions.clipboard'
import { createTreeExpressionBuilderExpressionActionsExposed } from './useTreeExpressionBuilderExpressionActions.exposed'
import { createTreeExpressionBuilderLifecycleActions } from './useTreeExpressionBuilderExpressionActions.lifecycle'
import type { TreeExpressionBuilderNotifier } from './treeExpressionBuilderNotifier'
import type { TreeExpressionBuilderState } from './useTreeExpressionBuilderExpressionActions.shared'
import { createTreeExpressionBuilderValidationActions } from './useTreeExpressionBuilderExpressionActions.validation'

export function useTreeExpressionBuilderExpressionActions(
  state: TreeExpressionBuilderState,
  notifier: TreeExpressionBuilderNotifier,
) {
  const lifecycleActions = createTreeExpressionBuilderLifecycleActions(state, notifier)
  const clipboardActions = createTreeExpressionBuilderClipboardActions(state, notifier)
  const validationActions = createTreeExpressionBuilderValidationActions(state, notifier)

  return createTreeExpressionBuilderExpressionActionsExposed({
    lifecycleActions,
    clipboardActions,
    validationActions,
  })
}
