import { unref } from 'vue'
import type { ValueInputSwitchPanelProps } from '../switch-panel/types'
import type { CreateValueInputSwitchPanelBasePropsOptions } from './panel-props.base.types'

type ValueInputSwitchPanelBaseProps = Omit<
  ValueInputSwitchPanelProps,
  | 'selectedFunctionName'
  | 'functionCategories'
  | 'selectedFunction'
  | 'functionParameters'
  | 'functionExpression'
>

export function createValueInputSwitchPanelBaseProps(
  options: CreateValueInputSwitchPanelBasePropsOptions,
): ValueInputSwitchPanelBaseProps {
  const { props, controller, state } = options

  return {
    currentInputType: state.currentInputType.value,
    valueTypeOptions: state.valueTypeOptions.value,
    value: props.value,
    fieldType: props.fieldType,
    comparison: props.comparison,
    availableFields: props.availableFields,
    valueDataType: controller.getValueDataType(),
    placeholder: controller.getPlaceholder(),
    multiValues: unref(controller.multiValues),
    dateValue: unref(controller.dateValue),
    urlError: unref(controller.urlError),
    valueArrayIndex: controller.getValueArrayIndex(),
    getFieldTypeColor: controller.getFieldTypeColor,
    getFieldTooltip: controller.getFieldTooltipForValue,
  }
}
