import { checkBasicAviatorSyntax } from '../logic/treeExpressionBuilderLogic'
import type { TreeExpressionBuilderNotifier } from './treeExpressionBuilderNotifier'
import type { TreeExpressionBuilderState } from './useTreeExpressionBuilderExpressionActions.shared'

interface ValidationActions {
  validateExpressionManually: () => Promise<void>
}

export function createTreeExpressionBuilderValidationActions(
  state: TreeExpressionBuilderState,
  notifier: TreeExpressionBuilderNotifier,
): ValidationActions {
  const validateExpressionManually = async () => {
    if (!state.generatedExpression.value) {
      notifier.warning('请先构建表达式')
      return
    }

    state.validating.value = true
    try {
      const valid = checkBasicAviatorSyntax(state.generatedExpression.value) && state.allErrors.value.length === 0
      state.validationResult.value = valid
        ? { success: true }
        : { success: false, message: state.allErrors.value[0]?.message || '表达式校验失败' }

      if (valid) {
        notifier.success('表达式验证通过')
      } else {
        notifier.error(state.validationResult.value.message || '表达式验证失败')
      }
    } finally {
      state.validating.value = false
    }
  }

  return {
    validateExpressionManually,
  }
}
