import { useParameterInputController } from '../../../composables/useParameterInputController'
import { createParameterInputListeners } from './listeners'
import { createParameterInputState } from './state'
import { createParameterInputViewModel } from './viewModel'
import type { UseParameterInputBindingsOptions } from './types'

export function setupParameterInputBindings(options: UseParameterInputBindingsOptions) {
  const { props, emit } = options

  const controller = useParameterInputController({
    props,
    emitUpdateValue: (value) => emit('update:value', value),
    emitUpdateType: (paramName, type) => emit('update:type', paramName, type),
    emitUpdateValueDataType: (paramName, dataType) => emit('update:value-data-type', paramName, dataType),
  })

  const state = createParameterInputState(
    props,
    controller.getParameterInputType,
    controller.getAvailableParameterTypes,
  )

  const listeners = createParameterInputListeners({
    emit,
    changeParameterType: controller.changeParameterType,
    updateValue: controller.updateValue,
    updateMultiValue: controller.updateMultiValue,
    changeValueDataType: controller.changeValueDataType,
    updateNestedNode: controller.updateNestedNode,
    updateNestedParameterType: controller.updateNestedParameterType,
  })

  const viewModel = createParameterInputViewModel({
    props,
    controller,
    state,
  })

  return {
    state,
    listeners,
    viewModel,
  }
}
