import type { setupValueEditorBindings } from './setup'

interface CreateValueEditorExposedBindingsOptions {
  setupResult: ReturnType<typeof setupValueEditorBindings>
}

export function createValueEditorExposedBindings(options: CreateValueEditorExposedBindingsOptions) {
  const { state, panelProps, listeners } = options.setupResult

  return {
    isConditionMode: state.isConditionMode,
    conditionEditorProps: panelProps.conditionEditorProps,
    parameterEditorProps: panelProps.parameterEditorProps,
    conditionEditorListeners: listeners.conditionEditorListeners,
    parameterEditorListeners: listeners.parameterEditorListeners,
  }
}
