import { computed } from 'vue'
import type { ParameterInputViewModelState } from './view-model.types'

interface CreateParameterInputModeFlagsOptions {
  state: ParameterInputViewModelState
}

export function createParameterInputModeFlags(options: CreateParameterInputModeFlagsOptions) {
  const { state } = options

  const isValueMode = computed(() => state.currentParameterInputType.value === 'value')
  const isFieldMode = computed(() => state.currentParameterInputType.value === 'field')
  const isConditionMode = computed(() => state.currentParameterInputType.value === 'condition')
  const isLambdaMode = computed(() => state.currentParameterInputType.value === 'lambda')

  return {
    isValueMode,
    isFieldMode,
    isConditionMode,
    isLambdaMode,
  }
}
