import { createTreeNodeContentActionBindings } from './actions'
import { createTreeNodeContentDragBindings } from './drag'
import { createTreeNodeContentEditorBindings } from './editor'
import { createTreeNodeContentListeners } from './listeners'
import type { UseTreeNodeContentBindingsOptions } from './types'

export function setupTreeNodeContentBindings(options: UseTreeNodeContentBindingsOptions) {
  const dragBindings = createTreeNodeContentDragBindings(options.emit)
  const editorBindings = createTreeNodeContentEditorBindings(options.emit)
  const actionBindings = createTreeNodeContentActionBindings(options.emit)
  const listeners = createTreeNodeContentListeners({
    dragBindings,
    editorBindings,
    actionBindings,
  })

  return {
    dragBindings,
    listeners,
  }
}
