<template>
  <ConditionTextValueInput
    v-if="fieldType === 'number'"
    :model-value="value"
    :placeholder="placeholder"
    compact
    v-on="valueListeners"
  />

  <ConditionBooleanSelect
    v-else-if="valueDataType === 'boolean'"
    :model-value="value"
    v-on="valueListeners"
  />

  <ConditionTextValueInput
    v-else
    :model-value="value"
    :placeholder="placeholder"
    v-on="valueListeners"
  />
</template>

<script setup lang="ts">
import type { NodeValue } from '../../../../../../infrastructure/engine/types'
import ConditionBooleanSelect from '../ConditionBooleanSelect.vue'
import ConditionTextValueInput from '../ConditionTextValueInput.vue'

defineProps<{
  value: NodeValue
  fieldType?: string
  valueDataType: string
  placeholder: string
}>()

const emit = defineEmits<{
  (e: 'update:value', value: NodeValue): void
}>()

const valueListeners = {
  'update:model-value': (value: NodeValue) => emit('update:value', value),
} as const
</script>
