import { createFunctionRefParametersExposedBindings } from './parameters-bindings/exposed'
import { setupFunctionRefParametersBindings } from './parameters-bindings/setup'
import type { UseFunctionRefParametersBindingsOptions } from './parameters-bindings/types'

export type { FunctionRefParametersEmits, UseFunctionRefParametersBindingsOptions } from './parameters-bindings/types'

export function useFunctionRefParametersBindings(options: UseFunctionRefParametersBindingsOptions) {
  const setupResult = setupFunctionRefParametersBindings(options)
  return createFunctionRefParametersExposedBindings({ setupResult })
}
