import type { NodeValue } from '../../infrastructure/engine/types'
import { createBasicValueActions } from './useParameterInputController.actions.value.basic'
import { createChangeParameterTypeAction } from './useParameterInputController.actions.parameter-type'
import { createChangeValueDataTypeAction } from './useParameterInputController.actions.value-data-type'
import { createInitializeLambdaParameterAction } from './useParameterInputController.actions.lambda-init'
import type {
  ParameterInputControllerState,
  UseParameterInputControllerActionsOptions,
} from './useParameterInputController.actions.shared'

interface ParameterInputValueActions {
  initializeLambdaParameter: () => void
  updateValue: (value: NodeValue) => void
  updateMultiValue: (values: string[]) => void
  updateFormatValue: (value: NodeValue) => void
  updateTimezoneValue: (value: NodeValue) => void
  changeValueDataType: (dataType: string) => void
  changeParameterType: (type: string) => void
}

export function createParameterInputValueActions(
  state: ParameterInputControllerState,
  options: UseParameterInputControllerActionsOptions,
): ParameterInputValueActions {
  const basicValueActions = createBasicValueActions({
    emitUpdateValue: options.emitUpdateValue,
  })

  const initializeLambdaParameter = createInitializeLambdaParameterAction(state, options)
  const changeValueDataType = createChangeValueDataTypeAction(state, options)
  const changeParameterType = createChangeParameterTypeAction(state, options)

  return {
    initializeLambdaParameter,
    updateValue: basicValueActions.updateValue,
    updateMultiValue: basicValueActions.updateMultiValue,
    updateFormatValue: basicValueActions.updateFormatValue,
    updateTimezoneValue: basicValueActions.updateTimezoneValue,
    changeValueDataType,
    changeParameterType,
  }
}
