import { createTreeNodeEditorPanelForwarders } from './editor-panel-bindings/forwarders'
import { createTreeNodeEditorPanelListeners } from './editor-panel-bindings/listeners'
import type { TreeNodeEditorPanelEmits } from './editor-panel-bindings/types'

export type { TreeNodeEditorPanelEmits } from './editor-panel-bindings/types'

interface UseTreeNodeEditorPanelBindingsOptions {
  emit: TreeNodeEditorPanelEmits
}

export function useTreeNodeEditorPanelBindings(options: UseTreeNodeEditorPanelBindingsOptions) {
  const bindings = createTreeNodeEditorPanelForwarders(options.emit)
  const listeners = createTreeNodeEditorPanelListeners({ bindings })

  return {
    conditionListeners: listeners.conditionListeners,
    groupListeners: listeners.groupListeners,
  }
}
