import type { FunctionParameter, NodeValue, TreeNode } from '../../infrastructure/engine/types'

export function getParameterActualValue(node: TreeNode, paramName: string): NodeValue {
  const param = node.parameters?.find((item) => item.name === paramName)
  if (!param) {
    return undefined
  }
  if (param.isNested && param.nestedNode) {
    return param.nestedNode
  }
  return param.value
}

export function getParameterWithValue(node: TreeNode, paramDef: FunctionParameter): FunctionParameter {
  const savedParam = node.parameters?.find((item) => item.name === paramDef.name)
  if (!savedParam) {
    return paramDef
  }

  const merged: FunctionParameter = {
    name: savedParam.name || paramDef.name,
    description: paramDef.description,
    type: savedParam.type || paramDef.type,
    required: paramDef.required,
    valueType: savedParam.valueType || paramDef.valueType,
  }

  if ('value' in savedParam) {
    merged.value = savedParam.value
  } else if ('value' in paramDef) {
    merged.value = paramDef.value
  }

  if ('nestedNode' in savedParam) {
    merged.nestedNode = savedParam.nestedNode
  } else if ('nestedNode' in paramDef) {
    merged.nestedNode = paramDef.nestedNode
  }

  if ('isNested' in savedParam) {
    merged.isNested = savedParam.isNested
  } else if ('isNested' in paramDef) {
    merged.isNested = paramDef.isNested
  }

  return merged
}
