import type { TreeNode } from '../../types'
import type { NodeInfo } from './types'

export function findNode(nodes: TreeNode[], nodeId: string, parent: TreeNode | null = null): NodeInfo {
  for (let i = 0; i < nodes.length; i++) {
    const node = nodes[i]
    if (node.id === nodeId) {
      return { node, parent, index: i }
    }

    if (node.children) {
      const result = findNode(node.children, nodeId, node)
      if (result.node) return result
    }
  }

  return { node: null, parent: null, index: -1 }
}

export function isDescendant(nodes: TreeNode[], ancestorId: string, descendantId: string): boolean {
  const checkNode = (items: TreeNode[]): boolean => {
    for (const node of items) {
      if (node.id === descendantId) return true
      if (node.children && checkNode(node.children)) return true
    }
    return false
  }

  const ancestor = findNode(nodes, ancestorId).node
  return ancestor?.children ? checkNode(ancestor.children) : false
}

export function updateNodeHierarchy(node: TreeNode, parentId: string | undefined, level: number) {
  node.parentId = parentId
  node.level = level

  if (node.children) {
    node.children.forEach((child) => updateNodeHierarchy(child, node.id, level + 1))
  }
}
