import { createAviatorExpressionBuilderExposedBindings } from './aviator-expression-builder-bindings/exposed'
import { setupAviatorExpressionBuilderBindings } from './aviator-expression-builder-bindings/setup'
import type {
  UseAviatorExpressionBuilderBindingsOptions,
} from './aviator-expression-builder-bindings/types'

export type {
  AviatorExpressionBuilderEmits,
  AviatorExpressionBuilderProps,
  UseAviatorExpressionBuilderBindingsOptions,
} from './aviator-expression-builder-bindings/types'

export function useAviatorExpressionBuilderBindings(options: UseAviatorExpressionBuilderBindingsOptions) {
  const setupResult = setupAviatorExpressionBuilderBindings(options)
  return createAviatorExpressionBuilderExposedBindings({ setupResult })
}
