import type { NodeValue, TreeNode } from '../../../../infrastructure/engine/types'
import type { UseParameterInputBindingsOptions } from './types'
import { createParameterInputBaseListeners } from './listeners.base'
import { createParameterInputConditionModeListeners } from './listeners.condition'
import { createParameterInputListenersExposed } from './listeners.exposed'

interface ParameterInputBindings {
  emit: UseParameterInputBindingsOptions['emit']
  changeParameterType: (type: string) => void
  updateValue: (value: NodeValue) => void
  updateMultiValue: (values: string[]) => void
  changeValueDataType: (dataType: string) => void
  updateNestedNode: (nodeId: string, updates: Partial<TreeNode>) => void
  updateNestedParameterType: (paramName: string, type: string) => void
}

export function createParameterInputListeners(bindings: ParameterInputBindings) {
  const baseListeners = createParameterInputBaseListeners({
    changeParameterType: bindings.changeParameterType,
    updateValue: bindings.updateValue,
    updateMultiValue: bindings.updateMultiValue,
    changeValueDataType: bindings.changeValueDataType,
  })

  const conditionListeners = createParameterInputConditionModeListeners({
    emit: bindings.emit,
    updateNestedNode: bindings.updateNestedNode,
    updateNestedParameterType: bindings.updateNestedParameterType,
  })

  return createParameterInputListenersExposed({
    baseListeners,
    conditionListeners,
  })
}
