import type { NodeValue } from '../../../../../../infrastructure/engine/types'
import type { ParameterValueInputSwitchEmits } from './types'

export function createParameterValueInputSwitchListeners(emit: ParameterValueInputSwitchEmits) {
  const valueListeners = {
    'update:model-value': (value: NodeValue) => emit('update:value', value),
  } as const

  const multiValueListeners = {
    'update:model-value': (values: string[]) => emit('update:multi-values', values),
  } as const

  const fallbackListeners = {
    'update:value': (value: NodeValue) => emit('update:value', value),
  } as const

  return {
    valueListeners,
    multiValueListeners,
    fallbackListeners,
  }
}
