import type { NodeValue } from '../../../../../../infrastructure/engine/types'
import type { FunctionRefParameterInputBodyEmits } from './input-body.types'

export function createFunctionRefParameterInputBodyListeners(emit: FunctionRefParameterInputBodyEmits) {
  const updateValueListeners = {
    'update:model-value': (value: NodeValue) => emit('update:value', value),
  } as const

  return {
    updateValueListeners,
  }
}
