import { createTreeNodeContentExposedBindings } from './content-bindings/exposed'
import { setupTreeNodeContentBindings } from './content-bindings/setup'
import type { UseTreeNodeContentBindingsOptions } from './content-bindings/types'

export type { TreeNodeContentEmits } from './content-bindings/types'
export type { UseTreeNodeContentBindingsOptions } from './content-bindings/types'

export function useTreeNodeContentBindings(options: UseTreeNodeContentBindingsOptions) {
  const setupResult = setupTreeNodeContentBindings(options)
  return createTreeNodeContentExposedBindings({ setupResult })
}
