import { createAviatorExpressionBuilderModalExposedBindings } from './aviator-expression-builder-modal-bindings/exposed'
import { setupAviatorExpressionBuilderModalBindings } from './aviator-expression-builder-modal-bindings/setup'
import type {
  UseAviatorExpressionBuilderModalBindingsOptions,
} from './aviator-expression-builder-modal-bindings/types'

export type {
  AviatorExpressionBuilderModalEmits,
  AviatorExpressionBuilderModalProps,
  UseAviatorExpressionBuilderModalBindingsOptions,
} from './aviator-expression-builder-modal-bindings/types'

export function useAviatorExpressionBuilderModalBindings(
  options: UseAviatorExpressionBuilderModalBindingsOptions,
) {
  const setupResult = setupAviatorExpressionBuilderModalBindings(options)
  return createAviatorExpressionBuilderModalExposedBindings({ setupResult })
}
