import type { createTreeNodeControllerBindings } from './controller'

export function createTreeNodeShellListeners(
  controller: ReturnType<typeof createTreeNodeControllerBindings>,
) {
  return {
    'node-dragover': controller.handleDragOver,
    'node-dragleave': controller.handleDragLeave,
    'node-drop': controller.handleDrop,
  } as const
}
