import type { FunctionParameterUpdatePayload } from '../function-ref/types'
import type { FunctionRefEditorEmits } from './types'

export function createFunctionRefEditorForwarders(emit: FunctionRefEditorEmits) {
  const onUpdateFunction = (value: string) => emit('update:function', value)
  const onUpdateParameter = (data: FunctionParameterUpdatePayload) => emit('update:parameter', data)

  return {
    onUpdateFunction,
    onUpdateParameter,
  }
}
