import type { TreeNode } from '../../types'
import { cloneDataTypes, generateCopiedNodeId } from './copy-utils'

interface ReassignCopiedSubtreeIdsOptions {
  targetNode: TreeNode
  parameterDataTypes: Map<string, Map<string, string>>
  parentId?: string
}

export function reassignCopiedSubtreeIds(options: ReassignCopiedSubtreeIdsOptions) {
  const { targetNode, parameterDataTypes, parentId } = options

  if (parentId) {
    targetNode.parentId = parentId
  }

  if (!targetNode.children) return

  targetNode.children.forEach((child) => {
    const oldChildId = child.id
    child.id = generateCopiedNodeId(child.type)
    child.parentId = targetNode.id

    cloneDataTypes(parameterDataTypes, oldChildId, child.id)
    reassignCopiedSubtreeIds({
      targetNode: child,
      parameterDataTypes,
      parentId: targetNode.id,
    })
  })
}
