import type { NodeValue } from '../../infrastructure/engine/types'
import { validateUrlInput } from '../logic/value-input'
import type {
  UseValueInputControllerActionsOptions,
  ValueInputControllerState,
} from './useValueInputController.shared'

export function useValueInputControllerValueActions(
  state: ValueInputControllerState,
  options: UseValueInputControllerActionsOptions,
) {
  const { props, emitUpdateValue } = options

  const updateValue = (value: NodeValue) => {
    emitUpdateValue(value)
  }

  const updateMultiValues = (values: string[]) => {
    emitUpdateValue(values)
  }

  const updateDateValue = (date: Date | undefined) => {
    if (date) {
      emitUpdateValue(date.toISOString())
    } else {
      emitUpdateValue('')
    }
  }

  const validateURL = () => {
    state.urlError.value = validateUrlInput(props.value)
  }

  const changeValueDataType = (dataType: string) => {
    state.userSelectedValueDataType.value = dataType
    if (props.value !== undefined && props.value !== null && props.value !== '') {
      emitUpdateValue(props.value)
    }
  }

  return {
    updateValue,
    updateMultiValues,
    updateDateValue,
    validateURL,
    changeValueDataType,
  }
}
