import { Message, Notification } from '@arco-design/web-vue'
import type { FunctionModeEditorControllerState } from './useFunctionModeEditorController.shared'
import { renderFunctionUsageContent } from './useFunctionModeEditorController.usage.render'

export function useFunctionModeEditorControllerUsageActions(
  state: FunctionModeEditorControllerState,
) {
  const copyExample = async (example: string) => {
    try {
      await navigator.clipboard.writeText(example)
      Message.success('示例已复制')
    } catch {
      Message.error('复制失败')
    }
  }

  const showFunctionUsage = () => {
    if (!state.selectedFunction.value) return

    const func = state.selectedFunction.value
    const content = renderFunctionUsageContent(func, {
      onCopyExample: () => copyExample(func.example),
    })

    Notification.info({
      title: `📖 ${func.displayName || func.name}`,
      content,
      duration: 30000,
      closable: true,
      position: 'topRight',
    })
  }

  return {
    showFunctionUsage,
  }
}
