import type { TreeNodeContentEmits } from './types'

export function createTreeNodeContentDragBindings(emit: TreeNodeContentEmits) {
  const onDragStart = (event: DragEvent) => emit('drag-start', event)
  const onDragEnd = (event: DragEvent) => emit('drag-end', event)
  const onToggleExpanded = () => emit('toggle-expanded')

  return {
    onDragStart,
    onDragEnd,
    onToggleExpanded,
  }
}
