import { type Ref, computed } from 'vue'
import type { DragPosition } from '../../../composables/useTreeNodeController.types'
import type { TreeNodeViewProps } from '../types'

interface CreateTreeNodeClassesOptions {
  props: TreeNodeViewProps
  isDragOver: Ref<boolean>
  dragPosition: Ref<DragPosition | null>
  hasError: Ref<boolean>
}

export function createTreeNodeClasses(options: CreateTreeNodeClassesOptions) {
  const { props, isDragOver, dragPosition, hasError } = options

  return computed(() => ({
    'node-condition': props.node.type === 'condition' && !props.node.functionName,
    'node-function': props.node.type === 'condition' && Boolean(props.node.functionName),
    'node-group': props.node.type === 'group',
    'node-expanded': props.node.type === 'group' && props.node.expanded,
    'node-collapsed': props.node.type === 'group' && !props.node.expanded,
    'drag-over': isDragOver.value,
    'drag-before': dragPosition.value === 'before',
    'drag-after': dragPosition.value === 'after',
    'drag-inside': dragPosition.value === 'inside',
    'has-error': hasError.value,
  }))
}
